/*
 * AQA A-Level Economics (7136) — Exam Practice Question Bank
 * All written/exam-style questions with AQA command words and mark schemes.
 * ~20 questions per topic, varying from 1-mark to 6-mark questions.
 */
const ECONOMICS_AQA_PRACTICE = {
  '3.1.1': {
    name: 'Economic Problem & Methodology',
    questions: [
      { q: 'State what is meant by the term scarcity.', marks: 1, markScheme: 'Resources/factors of production are limited/finite while wants are unlimited/infinite (1 mark).' },
      { q: 'State one example of a renewable resource.', marks: 1, markScheme: 'Solar energy / wind energy / timber / fish stocks (any valid renewable resource for 1 mark).' },
      { q: 'Define the term opportunity cost.', marks: 2, markScheme: 'The next best alternative forgone (1 mark) when a choice is made between competing uses of scarce resources (1 mark).' },
      { q: 'Define the term factors of production.', marks: 2, markScheme: 'The inputs/resources used in the production of goods and services (1 mark). They are land, labour, capital, and enterprise (1 mark).' },
      { q: 'Identify whether the following statement is positive or normative: "The UK inflation rate was 2.3% in March." Explain your answer.', marks: 2, markScheme: 'Positive (1 mark). It is a factual statement that can be tested/verified against data (1 mark).' },
      { q: 'Using a PPF diagram, explain what is meant by productive efficiency.', marks: 3, diagram: true, markScheme: 'Correctly drawn PPF with two goods on axes (1 mark). A point on the PPF is identified as productively efficient (1 mark). Explanation: all resources are fully and efficiently employed so it is not possible to produce more of one good without producing less of another (1 mark).' },
      { q: 'Explain, using a PPF diagram, how economic growth can be illustrated.', marks: 3, diagram: true, markScheme: 'Correctly drawn PPF (1 mark). An outward shift of the PPF shown (1 mark). Explanation: the shift represents an increase in the productive capacity of the economy, enabling more of both goods to be produced (1 mark).' },
      { q: 'Explain the difference between a movement from inside the PPF to a point on the PPF, and an outward shift of the PPF.', marks: 3, markScheme: 'Moving from inside to on the PPF represents using previously unemployed/inefficiently used resources more efficiently (1 mark). An outward shift represents an increase in the total quantity or quality of resources available (1 mark). The first is about efficiency; the second is about capacity/growth (1 mark).' },
      { q: 'Explain why the PPF is typically concave to the origin.', marks: 3, markScheme: 'Resources are not perfectly substitutable between producing different goods (1 mark). The law of diminishing returns/increasing opportunity costs applies as resources are transferred (1 mark). Each additional unit of one good requires giving up increasing amounts of the other (1 mark).' },
      { q: 'Explain two reasons why a government faces the problem of scarcity.', marks: 4, markScheme: 'Government has limited tax revenue/budget so cannot fund all desired programmes (1 mark). Spending on one area (e.g., defence) means less available for another (e.g., education), illustrating opportunity cost (1 mark). Demand for public services (healthcare, infrastructure) exceeds available resources (1 mark). Government must make choices about resource allocation, prioritising some needs over others (1 mark).' },
      { q: 'Explain, using an example, what is meant by derived demand for a factor of production.', marks: 3, markScheme: 'Derived demand means demand for a factor of production that arises from demand for the final good it helps produce (1 mark). For example, demand for bricklayers is derived from demand for new houses (1 mark). If demand for housing rises, demand for bricklayers increases (1 mark).' },
      { q: 'Explain one advantage and one disadvantage of using economic models.', marks: 4, markScheme: 'Advantage: models simplify complex reality, allowing economists to isolate and analyse key relationships between variables (1 mark). This helps in understanding cause and effect and making predictions (1 mark). Disadvantage: models rely on assumptions (e.g., ceteris paribus, rationality) that may not hold in reality (1 mark). This means predictions may be inaccurate when applied to the real world where many variables change simultaneously (1 mark).' },
      { q: 'Explain how comparative advantage relates to opportunity cost.', marks: 3, markScheme: 'A country has comparative advantage in producing a good if it can produce it at a lower opportunity cost than another country (1 mark). Opportunity cost is measured as the amount of the other good that must be forgone (1 mark). Even if a country is less efficient in absolute terms, it benefits from specialising in the good with the lowest opportunity cost (1 mark).' },
      { q: 'Explain why a point beyond the PPF is unattainable in the short run.', marks: 2, markScheme: 'A point beyond the PPF requires more resources than are currently available (1 mark). With existing factors of production and technology, this level of output cannot be reached (1 mark).' },
      { q: 'Explain how behavioural economics challenges traditional consumer theory.', marks: 4, markScheme: 'Traditional theory assumes consumers are rational utility maximisers with perfect information (1 mark). Behavioural economics identifies systematic biases: anchoring (relying too heavily on first information), loss aversion (weighting losses more than gains), present bias (overvaluing immediate gratification) (1 mark for any two). These mean consumers make predictable errors/do not always maximise utility (1 mark). Policy implications: nudges can improve decisions without restricting choice (1 mark).' },
      { q: 'A country produces only two goods: wheat and cloth. Draw a PPF diagram and identify a point representing unemployment of resources. Explain your answer.', marks: 4, diagram: true, markScheme: 'Correctly labelled PPF with wheat and cloth on axes (1 mark). Point inside the PPF clearly marked (1 mark). Explanation: a point inside the frontier means the country is not using all its resources efficiently (1 mark). Moving to a point on the frontier would increase output of one or both goods without reducing the other (1 mark).' },
      { q: 'Explain why economics is sometimes described as a social science rather than a natural science.', marks: 3, markScheme: 'Economics studies human behaviour and social interactions rather than physical phenomena (1 mark). It cannot easily conduct controlled experiments because many variables affect the economy simultaneously (1 mark). Human behaviour is less predictable than physical processes, making precise prediction difficult (1 mark).' },
      { q: 'Explain the role of the entrepreneur as a factor of production.', marks: 3, markScheme: 'The entrepreneur combines the other three factors of production (land, labour, capital) to produce goods and services (1 mark). They take on risk and uncertainty in business decisions (1 mark). Their reward is profit, and they innovate and organise production processes (1 mark).' },
      { q: 'Evaluate the claim that a free market economy allocates resources more efficiently than a planned economy.', marks: 6, markScheme: 'Free market strengths: price mechanism signals consumer preferences efficiently; profit incentive drives innovation and cost reduction; consumer sovereignty ensures production reflects demand. Free market weaknesses: fails with externalities, public goods, and merit goods; can lead to monopoly power and inequality; short-termism. Planned economy strengths: can prioritise social welfare, reduce inequality, and provide public goods. Planned economy weaknesses: lacks price signals leading to misallocation; no profit incentive creates X-inefficiency; information problems make central planning difficult. Evaluation: neither system is perfectly efficient; most economies are mixed. The relative efficiency depends on the specific good or market being considered and the quality of government institutions.' },
      { q: 'Evaluate the usefulness of the PPF model for understanding real-world economic choices.', marks: 6, markScheme: 'Useful: clearly illustrates opportunity cost, efficiency, and growth concepts; helps visualise trade-offs between goods; shows the impact of resource changes. Limitations: assumes only two goods when economies produce millions; assumes fixed technology (in the short run); does not show distribution or quality of output; ignores externalities and non-market factors; static model that does not capture dynamic changes. Evaluation: valuable as a teaching tool and conceptual framework but too simplified for actual policy decisions; should be used alongside other analytical tools.' },
      { q: 'State one characteristic of a free market economy.', marks: 1, markScheme: 'Resources are allocated through the price mechanism / private ownership of factors of production / minimal government intervention / consumer sovereignty (any one for 1 mark).' },
      { q: 'Define the term ceteris paribus.', marks: 1, markScheme: 'All other things being equal / holding all other variables constant (1 mark).' },
      { q: 'Define the term capital as a factor of production.', marks: 2, markScheme: 'Capital refers to man-made/manufactured resources used in the production of goods and services (1 mark). Examples include machinery, equipment, factories, and tools (1 mark).' },
      { q: 'Explain the difference between a positive and normative economic statement.', marks: 2, markScheme: 'A positive statement is factual and can be tested or verified against evidence (1 mark). A normative statement involves a value judgement or opinion about what should happen and cannot be objectively tested (1 mark).' },
      { q: 'Explain, using a PPF diagram, how an improvement in technology in one industry only would affect the PPF.', marks: 3, diagram: true, markScheme: 'Correctly drawn PPF with two goods on axes (1 mark). The PPF pivots outward on the axis of the good whose technology improved, while the other intercept remains unchanged (1 mark). Explanation: more of that good can now be produced with the same resources, but maximum output of the other good is unchanged (1 mark).' },
      { q: 'Explain why the basic economic problem exists in all types of economies.', marks: 3, markScheme: 'All economies face the fundamental problem that resources (land, labour, capital, enterprise) are finite/scarce (1 mark). Human wants are unlimited and constantly expanding (1 mark). Therefore every economy, whether free market, planned, or mixed, must make choices about what to produce, how to produce, and for whom to produce (1 mark).' },
      { q: 'Explain how a mixed economy attempts to address the economic problem.', marks: 3, markScheme: 'A mixed economy combines elements of both free market and planned systems (1 mark). The private sector allocates some resources through the price mechanism while the government intervenes to correct market failures and provide public services (1 mark). This aims to achieve both allocative efficiency and equity goals that neither system alone can fully deliver (1 mark).' },
      { q: 'Explain two limitations of the assumption of rational economic behaviour.', marks: 4, markScheme: 'Consumers may lack perfect information about prices, quality, and alternatives, leading to sub-optimal decisions (1 mark). This means they cannot always maximise utility as the rational model predicts (1 mark). Behavioural biases such as herd behaviour, status quo bias, and framing effects mean people systematically deviate from rational choice (1 mark). These predictable errors suggest traditional models overestimate consumer rationality (1 mark).' },
      { q: 'Explain how an increase in immigration could affect a country\'s PPF.', marks: 3, markScheme: 'Immigration increases the quantity of labour available as a factor of production (1 mark). This increases the economy\'s productive potential, causing the PPF to shift outward (1 mark). The country can now produce more of both goods than before, representing economic growth (1 mark).' },
      { q: 'Explain the difference between absolute advantage and comparative advantage.', marks: 3, markScheme: 'Absolute advantage means a country can produce a good using fewer resources than another country (1 mark). Comparative advantage means a country can produce a good at a lower opportunity cost than another country (1 mark). Trade is beneficial when based on comparative advantage even if one country has absolute advantage in both goods (1 mark).' },
      { q: 'Explain the concept of the margin in economic decision-making.', marks: 2, markScheme: 'Economic decisions are typically made at the margin, meaning agents consider the additional (marginal) cost and benefit of one more unit (1 mark). A rational agent continues an activity as long as marginal benefit exceeds marginal cost (1 mark).' },
      { q: 'Explain two ways in which government intervention in a market economy differs from resource allocation in a planned economy.', marks: 4, markScheme: 'In a market economy, government intervenes selectively to correct specific market failures (e.g., externalities, public goods) while leaving most allocation to the price mechanism (1 mark). In a planned economy, the state centrally determines what, how, and for whom to produce for most goods (1 mark). Market economy intervention uses tools like taxes and subsidies that work through the price mechanism (1 mark). Planned economies use directives, quotas, and state ownership to allocate resources directly (1 mark).' },
      { q: 'Explain why specialisation can increase total output.', marks: 3, markScheme: 'Workers or countries focus on tasks or goods where they have a comparative advantage or greatest skill (1 mark). Repetition and focus leads to increased productivity through practice, better use of tools, and reduced time switching between tasks (division of labour) (1 mark). This means total output is greater than if each worker or country tried to produce everything themselves (1 mark).' },
      { q: 'Explain two possible disadvantages of specialisation for an economy.', marks: 4, markScheme: 'Over-reliance on a narrow range of exports makes the economy vulnerable to external shocks such as a fall in global commodity prices (1 mark). This can cause severe economic disruption if demand for the specialised product declines (1 mark). Workers performing repetitive tasks may experience boredom and demotivation, reducing productivity and job satisfaction (1 mark). Structural unemployment may occur if demand patterns change and specialised workers lack transferable skills (1 mark).' },
      { q: 'Using a PPF diagram, explain the concept of reallocation of resources.', marks: 3, diagram: true, markScheme: 'Correctly drawn PPF with two goods on axes (1 mark). A movement along the PPF from one point to another is shown (1 mark). Explanation: moving along the PPF represents transferring resources from the production of one good to another, illustrating the trade-off and opportunity cost of the reallocation (1 mark).' },
      { q: 'Explain what is meant by bounded rationality.', marks: 2, markScheme: 'Bounded rationality means that decision-makers have limited cognitive ability, time, and information (1 mark). As a result, they use rules of thumb or heuristics rather than fully optimising, leading to satisfactory rather than optimal outcomes (1 mark).' },
      { q: 'Evaluate the view that free trade based on comparative advantage always benefits all countries.', marks: 6, markScheme: 'Arguments for: allows specialisation, increases total world output, lower consumer prices, wider choice, dynamic efficiency gains. Arguments against: assumes no transport costs or trade barriers; may cause structural unemployment in declining industries; infant industries may be unable to compete; terms of trade may favour developed countries; environmental costs of increased trade; assumes factors are mobile. Evaluation: comparative advantage provides a strong theoretical case but real-world frictions mean gains are not equally shared; complementary policies (retraining, social safety nets) may be needed to ensure benefits are widely distributed.' },
      { q: 'Evaluate whether behavioural economics has made traditional economic theory obsolete.', marks: 6, markScheme: 'Behavioural contributions: identifies systematic biases (loss aversion, anchoring, present bias); explains real-world anomalies traditional theory cannot; has practical policy applications (nudges, default options). Traditional theory strengths: provides powerful predictive frameworks; works well in aggregate even if individuals deviate; forms basis of welfare economics and efficiency analysis. Evaluation: behavioural economics complements rather than replaces traditional theory; both have explanatory value in different contexts; modern economics increasingly integrates insights from both approaches.' },
      { q: 'Explain why land is considered a fixed factor of production in the short run.', marks: 2, markScheme: 'In the short run, the total amount of land available to a firm or economy cannot be significantly increased (1 mark). A firm cannot quickly acquire new premises or agricultural land, so it must work within its existing land resources while varying other inputs like labour (1 mark).' },
      { q: 'Explain the concept of consumer sovereignty and how it operates in a market economy.', marks: 3, markScheme: 'Consumer sovereignty means consumers ultimately determine what is produced through their spending decisions (1 mark). Firms respond to consumer demand signals transmitted through the price mechanism; goods in high demand command higher prices and attract more resources (1 mark). Producers who fail to meet consumer preferences lose revenue and may exit the market, while those who satisfy demand earn profit (1 mark).' }
    ]
  },
  '3.1.2': {
    name: 'Price Determination',
    questions: [
      { q: 'State the law of demand.', marks: 1, markScheme: 'Ceteris paribus, as price rises, quantity demanded falls / there is an inverse relationship between price and quantity demanded (1 mark).' },
      { q: 'State one non-price determinant of demand.', marks: 1, markScheme: 'Consumer income / tastes and preferences / price of substitutes or complements / population / advertising (any one for 1 mark).' },
      { q: 'Define the term income elasticity of demand.', marks: 2, markScheme: 'YED measures the responsiveness of quantity demanded (1 mark) to a change in consumer income (1 mark). Formula: % change in QD / % change in income.' },
      { q: 'State two factors that influence price elasticity of supply.', marks: 2, markScheme: 'Availability of spare capacity/stocks (1 mark). Time period (short run vs long run) (1 mark). Other valid: availability of raw materials, ease of switching production.' },
      { q: 'Using a supply and demand diagram, show the effect of an increase in consumer income on the market for a normal good.', marks: 3, diagram: true, markScheme: 'Correctly drawn supply and demand diagram with labels (1 mark). Demand curve shifts to the right (1 mark). New equilibrium showing higher price and higher quantity (1 mark).' },
      { q: 'Using a diagram, explain the effect of an indirect tax on the market for cigarettes.', marks: 4, diagram: true, markScheme: 'Correctly drawn supply and demand diagram (1 mark). Supply curve shifts upward/leftward by the amount of the tax (1 mark). New equilibrium shows higher price and lower quantity (1 mark). Show the tax incidence split between consumers (higher price) and producers (lower effective price received) (1 mark).' },
      { q: 'Explain the relationship between PED and total revenue for a firm.', marks: 3, markScheme: 'If demand is price inelastic (PED between 0 and -1), a price increase leads to a proportionally smaller fall in quantity, so total revenue rises (1 mark). If demand is price elastic (PED greater than -1 in absolute terms), a price increase leads to a proportionally larger fall in quantity, so total revenue falls (1 mark). At unitary elasticity (PED = -1), total revenue is unchanged by price changes (1 mark).' },
      { q: 'The PED for a product is -0.5 and the current price is 10 pounds with 200 units sold. Calculate the effect on quantity demanded if price rises to 12 pounds.', marks: 3, markScheme: 'Price change = 20% increase (1 mark). % change in QD = PED x % change in price = -0.5 x 20% = -10% (1 mark). New quantity = 200 - 20 = 180 units (1 mark).' },
      { q: 'Using a diagram, explain the concept of consumer surplus.', marks: 3, diagram: true, markScheme: 'Correctly drawn supply and demand diagram with equilibrium price and quantity (1 mark). Consumer surplus identified as the area between the demand curve and the equilibrium price line (1 mark). Explanation: it represents the difference between what consumers are willing to pay and the market price (1 mark).' },
      { q: 'Explain how the imposition of a minimum price above equilibrium leads to excess supply.', marks: 3, markScheme: 'A minimum price is set above the equilibrium/market clearing price (1 mark). At this higher price, quantity supplied exceeds quantity demanded (1 mark). The resulting surplus/excess supply means not all output can be sold at the minimum price, potentially requiring government purchase or storage (1 mark).' },
      { q: 'Explain the likely impact of a fall in the price of a substitute good on the market for a product.', marks: 3, markScheme: 'If the price of a substitute falls, consumers switch away from the original product to the cheaper substitute (1 mark). This decreases demand for the original product, shifting its demand curve to the left (1 mark). Equilibrium price and quantity of the original product both fall (1 mark).' },
      { q: 'Explain why agricultural markets often experience price instability.', marks: 4, markScheme: 'Supply is price inelastic in the short run because production takes time (growing season) and is affected by weather (1 mark). Demand for food is also price inelastic as it is a necessity (1 mark). Small shifts in supply (e.g., due to bad harvest) lead to large price changes when both curves are inelastic (1 mark). The cobweb model shows how time lags between production decisions and output can cause cyclical price fluctuations (1 mark).' },
      { q: 'Explain how knowledge of YED helps a firm plan for changes in the economic cycle.', marks: 4, markScheme: 'Luxury goods (YED > 1) see demand rise faster than income in booms but fall sharply in recessions (1 mark). The firm can prepare by building capacity during recovery and managing costs during downturns (1 mark). Inferior goods (negative YED) see demand rise during recessions as consumers trade down (1 mark). Firms selling inferior goods may see counter-cyclical demand patterns, helping with planning (1 mark).' },
      { q: 'Explain how the incidence of an indirect tax depends on the price elasticity of demand and supply.', marks: 4, markScheme: 'The more inelastic demand is relative to supply, the greater the proportion of the tax borne by consumers through higher prices (1 mark). This is because consumers cannot easily reduce consumption (1 mark). The more inelastic supply is relative to demand, the greater the proportion borne by producers through lower net prices (1 mark). The actual split depends on the relative elasticities of demand and supply (1 mark).' },
      { q: 'Using a diagram, explain how a subsidy affects market equilibrium.', marks: 4, diagram: true, markScheme: 'Correctly drawn supply and demand diagram (1 mark). Supply curve shifts right/downward by the amount of the subsidy per unit (1 mark). New equilibrium shows lower price for consumers and higher quantity traded (1 mark). The effective price received by producers rises (market price + subsidy per unit) while the total cost to the government is shown as subsidy per unit x quantity (1 mark).' },
      { q: 'Explain why a Veblen good appears to contradict the law of demand.', marks: 3, markScheme: 'The law of demand states price and quantity demanded are inversely related (1 mark). For a Veblen good, a higher price increases desirability because it signals status, exclusivity, and prestige (1 mark). Demand may increase as price rises because the good is valued precisely because it is expensive (conspicuous consumption) (1 mark).' },
      { q: 'Explain why the XED between tea and coffee is positive while the XED between printers and ink is negative.', marks: 4, markScheme: 'Tea and coffee are substitutes: a rise in the price of coffee increases demand for tea, giving positive XED (1 mark)(1 mark). Printers and ink are complements: a rise in the price of printers reduces demand for ink, giving negative XED (1 mark)(1 mark).' },
      { q: 'Evaluate the effectiveness of buffer stock schemes in stabilising agricultural prices.', marks: 6, markScheme: 'How they work: government buys surplus when price is low (supporting price) and sells when price is high (capping price), using target price range. Benefits: reduces price volatility for farmers and consumers; stabilises farm incomes; encourages investment. Costs: expensive to store perishable goods; requires accurate target prices; encourages overproduction; eventual surplus must be dumped or destroyed; can distort international trade. Evaluation: effectiveness depends on funding, storage capacity, and accuracy of target price; historical experience (e.g., EU CAP) suggests significant government failure; alternative income support may be more efficient.' },
      { q: 'Evaluate whether minimum prices are an effective way to help farmers.', marks: 6, markScheme: 'Benefits: guarantees minimum income for farmers; prevents exploitation by powerful buyers; ensures food security. Drawbacks: creates excess supply that must be purchased or disposed of; cost to taxpayers/government; benefits larger farms disproportionately; may lead to inefficient producers remaining in the market; distorts international markets. Evaluation: may help in the short run but can create dependency and inefficiency; targeted income support or diversification grants may be more effective long-term solutions.' },
      { q: 'Explain what is meant by the term equilibrium price and describe what happens when the market is not in equilibrium.', marks: 4, markScheme: 'Equilibrium price is where quantity demanded equals quantity supplied and there is no tendency for price to change (1 mark). If price is above equilibrium, there is excess supply; producers cut prices to sell surplus, moving back to equilibrium (1 mark). If price is below equilibrium, there is excess demand; consumers bid up prices as they compete for scarce goods (1 mark). Market forces automatically adjust price towards equilibrium through the interaction of buyers and sellers (1 mark).' },
      { q: 'State the law of supply.', marks: 1, markScheme: 'Ceteris paribus, as price rises, quantity supplied rises / there is a positive/direct relationship between price and quantity supplied (1 mark).' },
      { q: 'State one condition necessary for a good to have high PED.', marks: 1, markScheme: 'Many close substitutes available / the good is a luxury / a high proportion of income is spent on the good / long time period (any one for 1 mark).' },
      { q: 'Define the term cross elasticity of demand.', marks: 2, markScheme: 'XED measures the responsiveness of quantity demanded of one good (1 mark) to a change in the price of another good (1 mark). Formula: % change in QD of good A / % change in price of good B.' },
      { q: 'Define the term producer surplus.', marks: 2, markScheme: 'Producer surplus is the difference between the price a producer receives for a good (1 mark) and the minimum price they would have been willing to accept (1 mark).' },
      { q: 'Using a supply and demand diagram, show the effect of a decrease in the costs of production on market equilibrium.', marks: 3, diagram: true, markScheme: 'Correctly drawn supply and demand diagram with labels (1 mark). Supply curve shifts to the right/downward (1 mark). New equilibrium showing lower price and higher quantity (1 mark).' },
      { q: 'The YED for organic food is +2.5. Explain what this means for a retailer if consumer incomes are expected to fall by 4%.', marks: 3, markScheme: 'YED of +2.5 means organic food is a luxury/normal good with income-elastic demand (1 mark). A 4% fall in income leads to a 10% fall in demand (2.5 x 4%) (1 mark). The retailer should expect a significant drop in sales and may need to adjust stock levels or diversify into inferior goods (1 mark).' },
      { q: 'Explain the difference between a shift of the demand curve and a movement along the demand curve.', marks: 3, markScheme: 'A movement along the demand curve is caused by a change in the price of the good itself and represents a change in quantity demanded (1 mark). A shift of the demand curve is caused by a change in a non-price factor (income, tastes, price of related goods) and represents a change in demand at every price level (1 mark). It is important to distinguish between the two because they have different causes and different effects on equilibrium (1 mark).' },
      { q: 'Using a diagram, explain the concept of producer surplus and how it changes when supply decreases.', marks: 4, diagram: true, markScheme: 'Correctly drawn supply and demand diagram with equilibrium price and quantity (1 mark). Producer surplus identified as the area between the supply curve and the equilibrium price line (1 mark). When supply shifts left, equilibrium price rises and quantity falls (1 mark). The effect on producer surplus is ambiguous: higher price increases it per unit but lower quantity reduces total; the net effect depends on PED (1 mark).' },
      { q: 'Explain why the PES for manufactured goods tends to be higher than for agricultural goods.', marks: 3, markScheme: 'Manufactured goods can be produced more quickly by increasing shifts, hiring workers, or using spare capacity (1 mark). Agricultural goods have long production cycles (growing seasons) and are dependent on natural factors like weather (1 mark). Therefore manufacturers can respond more quickly to price changes, giving higher PES, while agricultural output is harder to adjust in the short run (1 mark).' },
      { q: 'A firm sells 500 units at 8 pounds. PED is estimated at -1.5. Calculate the new quantity demanded if price rises to 9 pounds.', marks: 3, markScheme: 'Percentage price change = (9-8)/8 x 100 = 12.5% (1 mark). Percentage change in QD = -1.5 x 12.5% = -18.75% (1 mark). New QD = 500 - (0.1875 x 500) = 500 - 93.75 = approximately 406 units (1 mark).' },
      { q: 'Explain how a maximum price (price ceiling) set below equilibrium leads to excess demand.', marks: 3, markScheme: 'A maximum price is set below the equilibrium/market clearing price to make the good more affordable (1 mark). At this lower price, quantity demanded exceeds quantity supplied (1 mark). The resulting excess demand/shortage means some consumers who want to buy at this price cannot obtain the good, potentially leading to rationing, queuing, or black markets (1 mark).' },
      { q: 'Explain why the demand for petrol tends to be more price inelastic in the short run than the long run.', marks: 3, markScheme: 'In the short run, consumers are locked into existing travel patterns, car choices, and locations, making it difficult to reduce petrol consumption (1 mark). In the long run, consumers can adjust by buying fuel-efficient or electric cars, using public transport, or relocating closer to work (1 mark). Therefore the long-run PED is higher (more elastic) as consumers have more time to find substitutes and change habits (1 mark).' },
      { q: 'Explain how a change in the weather can cause price changes in the market for fresh fruit.', marks: 3, markScheme: 'Poor weather (drought, frost) reduces crop yields, shifting the supply curve to the left (1 mark). With demand relatively unchanged, equilibrium price rises and quantity falls (1 mark). Since both demand and supply for fresh fruit are relatively price inelastic in the short run, even a small supply shift causes a large price change (1 mark).' },
      { q: 'Explain the difference between a normal good and an inferior good in terms of YED.', marks: 2, markScheme: 'A normal good has a positive YED, meaning demand increases as income rises (1 mark). An inferior good has a negative YED, meaning demand falls as income rises because consumers switch to higher-quality alternatives (1 mark).' },
      { q: 'Using a diagram, explain how a price floor in the labour market can cause unemployment.', marks: 4, diagram: true, markScheme: 'Supply and demand diagram for labour with wage on y-axis and quantity of labour on x-axis (1 mark). Minimum wage set above the equilibrium wage (1 mark). At the higher wage, quantity of labour supplied exceeds quantity demanded (1 mark). The gap between supply and demand represents unemployment; firms hire fewer workers because labour costs are higher (1 mark).' },
      { q: 'Explain why total revenue is maximised when PED equals -1.', marks: 3, markScheme: 'When PED = -1 (unitary elasticity), the percentage change in quantity demanded exactly equals the percentage change in price (1 mark). Raising price reduces quantity by the same proportion, leaving total revenue unchanged; lowering price increases quantity by the same proportion (1 mark). At any PED more elastic than -1, cutting price raises revenue; at any PED less elastic, raising price raises revenue; revenue is at its maximum where these meet at PED = -1 (1 mark).' },
      { q: 'Evaluate the effectiveness of maximum prices as a method of helping low-income consumers.', marks: 6, markScheme: 'Benefits: makes essential goods affordable; directly reduces cost of living for the poor; politically popular. Problems: creates excess demand and shortages; may lead to black markets at higher prices; reduces producer surplus and may drive suppliers out of the market; requires rationing which may be inefficient or unfair; reduces quality as producers cut costs. Evaluation: may help in the short run but creates significant market distortions; alternative measures such as income support or subsidies may achieve similar aims with fewer side effects; effectiveness depends on enforcement and the size of the gap between the ceiling and equilibrium price.' },
      { q: 'Evaluate the usefulness of PED for a firm making pricing decisions.', marks: 6, markScheme: 'Useful: helps predict effect of price changes on revenue; guides pricing strategy (raise price for inelastic goods, lower for elastic); aids marketing and product positioning. Limitations: PED estimates are based on historical data and may not reflect future conditions; assumes ceteris paribus which rarely holds; PED varies along a linear demand curve; competitors may respond to price changes; difficult to measure accurately in practice. Evaluation: PED is a valuable analytical tool but should be used alongside other market intelligence; firms must consider dynamic competitive responses and the limitations of static elasticity estimates.' },
      { q: 'Explain why the supply curve for housing is typically very price inelastic in the short run.', marks: 3, markScheme: 'Construction of new housing takes considerable time due to planning permissions, design, and building work (1 mark). Land available for development is limited, especially in urban areas (1 mark). Even if house prices rise significantly, builders cannot quickly increase the supply of completed homes, making short-run supply very inelastic (1 mark).' },
      { q: 'Explain how the introduction of a successful advertising campaign would affect the demand curve for a product and its market equilibrium.', marks: 3, markScheme: 'A successful advertising campaign increases consumer awareness and desire for the product, shifting the demand curve to the right (1 mark). At every price level, quantity demanded is now higher than before (1 mark). The new equilibrium shows a higher price and a higher quantity traded in the market (1 mark).' }
    ]
  },
  '3.1.3': {
    name: 'Production Costs & Revenue',
    questions: [
      { q: 'State the formula for average cost.', marks: 1, markScheme: 'Average cost = Total cost / Output (quantity produced) (1 mark).' },
      { q: 'State one example of a fixed cost for a restaurant.', marks: 1, markScheme: 'Rent / lease payments / insurance / business rates (any one valid fixed cost for 1 mark).' },
      { q: 'Define the term marginal revenue.', marks: 2, markScheme: 'Marginal revenue is the additional/extra revenue (1 mark) gained from selling one more unit of output (1 mark).' },
      { q: 'Define the term minimum efficient scale.', marks: 2, markScheme: 'The minimum efficient scale is the lowest level of output (1 mark) at which long-run average costs are minimised / all economies of scale are fully exploited (1 mark).' },
      { q: 'Draw a diagram showing the typical short-run average cost (AC) and marginal cost (MC) curves. Mark the profit-maximising output if the firm is a price taker at price P.', marks: 4, diagram: true, markScheme: 'U-shaped AC curve correctly drawn (1 mark). U-shaped MC curve that crosses AC at its minimum point (1 mark). Horizontal demand/AR/MR line at price P for a price-taking firm (1 mark). Profit-maximising output marked where MC = MR (price line) with output identified on the x-axis (1 mark).' },
      { q: 'Explain the law of diminishing marginal returns using an example.', marks: 3, markScheme: 'In the short run, at least one factor is fixed (e.g., land for a farm) (1 mark). As more of a variable factor (e.g., workers) is added, eventually each additional worker adds less to total output (1 mark). Example: a small kitchen with more and more chefs eventually sees them getting in each other\'s way, reducing the extra output each one contributes (1 mark).' },
      { q: 'Explain why a firm making a loss in the short run may continue to produce rather than shut down.', marks: 3, markScheme: 'If price/AR is above average variable cost but below average total cost, the firm is making a contribution to fixed costs (1 mark). Fixed costs must be paid whether the firm produces or not (1 mark). By continuing to produce, losses are smaller than they would be if the firm shut down (where losses would equal total fixed costs) (1 mark).' },
      { q: 'Using a diagram, explain the long-run average cost curve and identify the minimum efficient scale.', marks: 4, diagram: true, markScheme: 'LRAC curve drawn showing economies of scale (falling section), possible constant returns, and diseconomies of scale (rising section) or L-shape (1 mark). Short-run average cost curves shown as tangent to the LRAC as an envelope curve (1 mark). MES marked at the output where LRAC first reaches its minimum (1 mark). Explanation that MES is the smallest output at which a firm can produce at lowest average cost (1 mark).' },
      { q: 'Explain two internal economies of scale available to a large manufacturing firm.', marks: 4, markScheme: 'Technical economies: large firms can afford large-scale specialised machinery/production lines that reduce unit costs through automation and efficiency (1 mark)(1 mark). Purchasing economies: buying raw materials in bulk allows the firm to negotiate lower unit prices from suppliers (1 mark)(1 mark). Other valid: financial (borrowing at lower rates), managerial (specialist managers), risk-bearing (diversification).' },
      { q: 'Explain the difference between internal and external economies of scale.', marks: 3, markScheme: 'Internal economies of scale are cost advantages that arise from the growth of an individual firm as it increases its own output (1 mark). External economies of scale benefit all firms in an industry and arise from the growth of the industry or its location (1 mark). Example: a cluster of tech firms in an area may attract specialist suppliers and skilled labour pools benefiting all firms (1 mark).' },
      { q: 'A firm\'s total costs are 5000 pounds at 100 units and 5080 pounds at 101 units. Calculate the marginal cost.', marks: 2, markScheme: 'MC = change in TC / change in output = (5080 - 5000) / (101 - 100) (1 mark) = 80 pounds (1 mark).' },
      { q: 'Explain why a monopolist\'s marginal revenue is less than its price.', marks: 3, markScheme: 'A monopolist faces a downward-sloping demand curve and must lower price on ALL units to sell one more (1 mark). The MR from the extra unit is the price of that unit MINUS the revenue lost from reducing price on all previous units (1 mark). Therefore MR < AR (price) and the MR curve lies below the demand/AR curve (1 mark).' },
      { q: 'Explain what is meant by supernormal profit and illustrate on a diagram.', marks: 4, diagram: true, markScheme: 'Supernormal/abnormal profit occurs when total revenue exceeds total cost including normal profit / AR > AC (1 mark). Diagram with AC, MC, AR, and MR curves (1 mark). Output at MC = MR, price read from demand curve, supernormal profit shown as the shaded rectangle between AR and AC at that output (1 mark). Explanation that this is profit above the minimum required to keep the firm in the industry (1 mark).' },
      { q: 'Explain two possible causes of diseconomies of scale.', marks: 4, markScheme: 'Communication difficulties: in large organisations information must pass through many layers, leading to delays, distortion, and misunderstanding (1 mark)(1 mark). Coordination problems: managing diverse operations across multiple sites becomes complex, leading to duplication, slow decision-making, and bureaucracy (1 mark)(1 mark). Other valid: worker alienation/lack of motivation, loss of control.' },
      { q: 'Explain the difference between the short run and the long run in economics.', marks: 3, markScheme: 'The short run is a time period in which at least one factor of production is fixed (e.g., factory size, land) (1 mark). The long run is a time period in which all factors of production are variable and can be changed (1 mark). The distinction is not about calendar time but about the ability to adjust all inputs (1 mark).' },
      { q: 'Explain what is meant by revenue maximisation as a business objective and how it differs from profit maximisation.', marks: 4, markScheme: 'Revenue maximisation occurs at the output where MR = 0 (total revenue is at its highest) (1 mark). Profit maximisation occurs at the output where MC = MR (1 mark). Revenue maximisation typically involves a higher output and lower price than profit maximisation (1 mark). Managers may prefer revenue maximisation because their rewards (salary, prestige) may be linked to firm size/turnover rather than profit (Baumol model) (1 mark).' },
      { q: 'Explain the concept of satisficing as a business objective.', marks: 3, markScheme: 'Satisficing means achieving a satisfactory level of profit rather than the maximum (Herbert Simon) (1 mark). It arises because of bounded rationality: managers have limited information and cognitive capacity (1 mark). Firms set acceptable targets for profit, market share, etc., rather than optimising any single variable, reflecting the competing interests of different stakeholders (1 mark).' },
      { q: 'Evaluate the view that economies of scale always lead to lower prices for consumers.', marks: 6, markScheme: 'Argument for: lower average costs from EoS can be passed on as lower prices, especially in competitive markets. Evidence: large supermarkets often offer lower prices than small shops. Argument against: firms with EoS may have monopoly power and choose to keep prices high and take supernormal profit; X-inefficiency may mean cost savings are not realised; barriers to entry from EoS reduce competition. Evaluation: whether lower costs translate to lower prices depends on market structure, competitive pressure, and contestability; regulation may be needed to ensure benefits reach consumers.' },
      { q: 'Evaluate the significance of the principal-agent problem for firm behaviour.', marks: 6, markScheme: 'The problem: separation of ownership (shareholders) and control (managers) means managers may pursue their own objectives (salary, empire building, quiet life) rather than profit maximisation. Evidence: executive pay packages, merger activity. Mitigating factors: performance-related pay, share options, threat of takeover, shareholder activism. Counter-arguments: in competitive markets, firms that deviate from profit maximisation are punished; many small firms are owner-managed. Evaluation: significance depends on firm size, ownership structure, and market competition; it is most relevant for large public companies with dispersed ownership.' },
      { q: 'Explain why average fixed cost falls continuously as output increases.', marks: 2, markScheme: 'Fixed costs do not change with output in the short run (1 mark). As output increases, the same fixed costs are spread over more units, so average fixed cost (TFC/Q) continuously declines (1 mark).' },
      { q: 'State the formula for marginal cost.', marks: 1, markScheme: 'Marginal cost = Change in total cost / Change in output (1 mark).' },
      { q: 'State one example of a variable cost for a bakery.', marks: 1, markScheme: 'Flour / sugar / eggs / packaging / energy for ovens (any one valid variable cost for 1 mark).' },
      { q: 'Define the term normal profit.', marks: 2, markScheme: 'Normal profit is the minimum level of profit required to keep a firm in an industry in the long run (1 mark). It occurs when total revenue equals total cost (AR = AC), where total cost includes an imputed cost for the entrepreneur\'s time and risk (1 mark).' },
      { q: 'Define the term total revenue.', marks: 2, markScheme: 'Total revenue is the total income a firm receives from selling its output (1 mark). It is calculated as price per unit multiplied by quantity sold (TR = P x Q) (1 mark).' },
      { q: 'Draw a diagram showing the relationship between marginal cost and average cost curves. Explain why MC crosses AC at the minimum of AC.', marks: 4, diagram: true, markScheme: 'U-shaped AC curve correctly drawn (1 mark). U-shaped MC curve that intersects AC at its lowest point (1 mark). When MC is below AC, AC is falling because each additional unit costs less than the average (1 mark). When MC is above AC, AC is rising because each additional unit costs more than the average; at the intersection MC = AC and AC is at its minimum (1 mark).' },
      { q: 'Explain the difference between fixed and variable costs using examples.', marks: 3, markScheme: 'Fixed costs do not change with the level of output in the short run, e.g., rent, insurance premiums (1 mark). Variable costs change directly with the level of output, e.g., raw materials, hourly wages (1 mark). Total cost is the sum of fixed and variable costs at any level of output (1 mark).' },
      { q: 'A firm produces 200 units with total costs of 10,000 pounds and total revenue of 14,000 pounds. Calculate the profit per unit.', marks: 2, markScheme: 'Total profit = 14,000 - 10,000 = 4,000 pounds (1 mark). Profit per unit = 4,000 / 200 = 20 pounds (1 mark).' },
      { q: 'Explain why the MC curve is typically U-shaped in the short run.', marks: 3, markScheme: 'Initially, as output increases, specialisation and better use of fixed factors cause marginal costs to fall (increasing marginal returns) (1 mark). Beyond a certain point, the law of diminishing marginal returns sets in as the fixed factor becomes overloaded (1 mark). Each additional unit of variable factor adds less to output, so the cost of each additional unit of output rises (1 mark).' },
      { q: 'Explain the difference between economies and diseconomies of scale.', marks: 3, markScheme: 'Economies of scale occur when long-run average costs fall as a firm increases its scale of production (1 mark). Diseconomies of scale occur when long-run average costs rise as a firm grows beyond its optimal size (1 mark). The LRAC curve is U-shaped (or L-shaped) reflecting economies of scale on the left, then diseconomies on the right (1 mark).' },
      { q: 'Explain why a firm\'s shut-down price in the short run is where AR equals AVC.', marks: 3, markScheme: 'If AR (price) is below AVC, the firm cannot cover its variable costs and loses more money by producing than by shutting down (1 mark). At AR = AVC, the firm just covers variable costs but makes no contribution to fixed costs (1 mark). Below this point, each unit sold increases losses, so the rational decision is to cease production in the short run (1 mark).' },
      { q: 'Explain two financial economies of scale available to large firms.', marks: 4, markScheme: 'Large firms can borrow at lower interest rates because banks view them as lower risk and they can offer more collateral (1 mark). This reduces the cost of capital for investment and expansion (1 mark). Large firms can also raise finance by issuing shares on the stock market, a source not available to small firms (1 mark). This gives them access to a wider pool of capital at potentially lower cost (1 mark).' },
      { q: 'Explain the difference between profit maximisation and sales maximisation as business objectives.', marks: 4, markScheme: 'Profit maximisation occurs at the output where MC = MR, producing the highest possible profit (1 mark). Sales maximisation occurs at the output where AR = AC (normal profit), producing the highest output while not making a loss (1 mark). Sales maximisation leads to higher output and lower price than profit maximisation (1 mark). Managers may prefer sales maximisation to grow market share, increase prestige, or deter entry (William Baumol\'s model) (1 mark).' },
      { q: 'Explain the concept of productive efficiency and where it occurs on a cost diagram.', marks: 3, markScheme: 'Productive efficiency means producing output at the lowest possible average cost (1 mark). On a cost diagram, it occurs at the minimum point of the average cost curve (1 mark). At this point, resources are being used in the most cost-effective way possible; producing at any other output level wastes resources (1 mark).' },
      { q: 'A firm\'s total revenue is 50,000 pounds from selling 1,000 units. If it sells one more unit and total revenue rises to 50,040 pounds, calculate the average revenue and marginal revenue.', marks: 2, markScheme: 'Average revenue = 50,000 / 1,000 = 50 pounds per unit (1 mark). Marginal revenue = 50,040 - 50,000 = 40 pounds (1 mark).' },
      { q: 'Explain what is meant by an external diseconomy of scale using an example.', marks: 3, markScheme: 'An external diseconomy of scale occurs when the growth of an industry raises costs for all firms within it (1 mark). Example: as an industry grows in a particular area, increased demand for local labour bids up wages for all firms (1 mark). Similarly, congestion and higher land prices in industrial clusters can raise costs for all businesses regardless of their individual size (1 mark).' },
      { q: 'Explain why a perfectly competitive firm\'s demand curve is also its marginal revenue and average revenue curve.', marks: 3, markScheme: 'A perfectly competitive firm is a price taker, so it can sell any quantity at the market price (1 mark). Each additional unit sold adds the same amount (the market price) to total revenue, so MR = price (1 mark). Since all units sell at the same price, average revenue also equals the market price, giving a horizontal AR = MR = D curve (1 mark).' },
      { q: 'Evaluate whether profit maximisation is the most realistic assumption about firm behaviour.', marks: 6, markScheme: 'For profit maximisation: standard economic assumption; shareholders want maximum returns; competitive pressure forces firms towards it; firms that do not will be taken over or exit. Against: managers may pursue their own goals (principal-agent problem); satisficing is more realistic given limited information; short-run profit maximisation may conflict with long-run growth; firms may pursue ethical or social objectives. Evaluation: profit maximisation is a useful theoretical benchmark but many firms pursue multiple objectives simultaneously; it is most realistic for small owner-managed firms and in highly competitive markets; larger firms with dispersed ownership often deviate from strict profit maximisation.' },
      { q: 'Evaluate the importance of economies of scale as a barrier to entry.', marks: 6, markScheme: 'How EoS act as barrier: incumbent firms producing at large scale have much lower unit costs; new entrants starting at small scale face higher average costs; they must either enter at large scale (requiring huge capital) or accept a cost disadvantage. Significance: most important in capital-intensive industries (airlines, car manufacturing, pharmaceuticals); can deter entry even in absence of other barriers. Counter-arguments: niche markets allow small-scale entry; innovation can leapfrog scale advantages; internet has reduced MES in many industries. Evaluation: EoS are a significant barrier in some industries but less so in services and digital markets; their importance varies by sector and over time as technology changes.' },
      { q: 'Explain the concept of the long run in relation to all factors being variable.', marks: 2, markScheme: 'In the long run, a firm can change all of its factors of production including factory size, technology, and number of sites (1 mark). This allows the firm to choose the optimal combination of inputs and scale of production, which is why the long-run cost curve envelopes all possible short-run cost curves (1 mark).' },
      { q: 'Explain how the principle of profit maximisation (MC = MR) applies when MC is rising.', marks: 3, markScheme: 'A profit-maximising firm produces where MC = MR, provided MC is rising through the MR curve (1 mark). If MC is below MR, producing one more unit adds more to revenue than to cost, so profit increases (1 mark). If MC is above MR, producing one more unit adds more to cost than revenue, so profit falls; only the rising MC intersection represents a maximum (1 mark).' }
    ]
  },
  '3.1.4': {
    name: 'Competitive & Concentrated Markets',
    questions: [
      { q: 'State one characteristic of a perfectly competitive market.', marks: 1, markScheme: 'Homogeneous products / many buyers and sellers / perfect information / no barriers to entry or exit / firms are price takers (any one for 1 mark).' },
      { q: 'State what is meant by interdependence in an oligopoly.', marks: 1, markScheme: 'Each firm must consider the likely reactions/responses of rival firms when making pricing or output decisions (1 mark).' },
      { q: 'Define the term barrier to entry.', marks: 2, markScheme: 'Barriers to entry are obstacles/factors (1 mark) that make it difficult or costly for new firms to enter a market and compete with existing firms (1 mark).' },
      { q: 'Define the term price discrimination.', marks: 2, markScheme: 'Price discrimination occurs when a firm charges different prices to different consumers (1 mark) for the same good/service where the price difference is not due to cost differences (1 mark).' },
      { q: 'Draw a diagram to show a perfectly competitive firm earning normal profit in long-run equilibrium.', marks: 4, diagram: true, markScheme: 'U-shaped MC and AC curves correctly drawn (1 mark). Horizontal demand/AR/MR line tangent to AC at its minimum point (1 mark). Firm produces where MC = MR at the minimum of AC (1 mark). Output and price correctly labelled; no supernormal profit because AR = AC (1 mark).' },
      { q: 'Draw a diagram showing a profit-maximising monopolist. Identify the level of supernormal profit.', marks: 4, diagram: true, markScheme: 'Downward-sloping AR (demand) curve with MR below it (1 mark). U-shaped MC and AC curves (1 mark). Output at MC = MR, price read up from demand curve (1 mark). Supernormal profit shown as shaded area between AR and AC at the profit-maximising output (1 mark).' },
      { q: 'Explain why a monopolist is allocatively inefficient.', marks: 3, markScheme: 'Allocative efficiency requires P = MC, meaning resources are allocated according to consumer preferences (1 mark). A monopolist produces where MC = MR to maximise profit, and since MR < P (downward-sloping demand), the price is set above MC (1 mark). This means consumers pay more than the marginal cost and output is below the socially optimal level, creating deadweight welfare loss (1 mark).' },
      { q: 'Explain the kinked demand curve model of oligopoly.', marks: 4, markScheme: 'Each firm assumes that if it raises price, rivals will not follow (demand is elastic above the kink) (1 mark). If it lowers price, rivals will match the cut (demand is inelastic below the kink) (1 mark). This creates a kink in the demand curve at the current price and a discontinuity in the MR curve (1 mark). The model explains price rigidity/stickiness because MC can shift within the MR gap without changing the profit-maximising price (1 mark).' },
      { q: 'Explain the prisoner\'s dilemma using the example of two firms deciding whether to advertise.', marks: 4, markScheme: 'Two firms each choose to advertise or not. If both advertise, costs are high and profits are shared (1 mark). If neither advertises, both save costs and earn moderate profits (collectively the best outcome) (1 mark). However, each firm has an individual incentive to advertise (to gain market share), so both advertise even though mutual non-advertising is better (1 mark). The dominant strategy for each firm is to advertise, leading to a Nash equilibrium that is not collectively optimal (1 mark).' },
      { q: 'Explain three conditions necessary for successful price discrimination.', marks: 3, markScheme: 'The firm must have market power/ability to set prices (not a price taker) (1 mark). The firm must be able to identify and separate consumers into groups with different PED (e.g., adults vs students) (1 mark). The firm must be able to prevent resale/arbitrage between groups (1 mark).' },
      { q: 'Explain how contestability affects the behaviour of a monopolist.', marks: 3, markScheme: 'In a contestable market, there are low barriers to entry and exit (especially low sunk costs) (1 mark). The threat of hit-and-run entry from potential competitors forces the monopolist to keep prices close to average cost (1 mark). This limits supernormal profit and may lead to behaviour similar to competitive firms despite having a single seller (1 mark).' },
      { q: 'Explain the concept of X-inefficiency and why it is associated with monopoly.', marks: 3, markScheme: 'X-inefficiency occurs when a firm produces at a cost above the minimum possible average cost (1 mark). It arises from a lack of competitive pressure, leading to organisational slack, waste, and poor cost control (1 mark). Monopolists protected by barriers to entry face less pressure to minimise costs compared to firms in competitive markets (1 mark).' },
      { q: 'Explain what is meant by a natural monopoly using a diagram.', marks: 4, diagram: true, markScheme: 'A natural monopoly exists in industries with very high fixed/infrastructure costs relative to marginal costs (1 mark). Diagram showing continuously falling LRAC curve over the relevant range of market demand (1 mark). One firm can supply the entire market at lower average cost than two or more firms (1 mark). Examples: water supply, rail network, electricity distribution (1 mark).' },
      { q: 'Explain the difference between tacit and overt collusion.', marks: 3, markScheme: 'Overt collusion is a formal/explicit agreement between firms to fix prices, share markets, or restrict output (e.g., a cartel like OPEC) (1 mark). Tacit collusion occurs when firms coordinate behaviour without formal agreement, e.g., through price leadership where smaller firms follow the pricing of a dominant firm (1 mark). Overt collusion is illegal in most countries while tacit collusion is harder to detect and regulate (1 mark).' },
      { q: 'Explain how non-price competition benefits consumers in an oligopolistic market.', marks: 3, markScheme: 'Firms compete through quality improvements, giving consumers better products (1 mark). Innovation and R&D lead to new features and product development (1 mark). Loyalty schemes, better customer service, and convenient locations improve the consumer experience (1 mark).' },
      { q: 'Explain why in monopolistic competition firms only earn normal profit in the long run.', marks: 3, markScheme: 'If firms earn supernormal profit in the short run, low barriers to entry attract new firms into the market (1 mark). New entrants increase supply of substitutes, reducing demand for each existing firm (demand curve shifts left) (1 mark). This continues until AR = AC and only normal profit is earned (1 mark).' },
      { q: 'Evaluate whether consumers benefit more from perfect competition or monopoly.', marks: 6, markScheme: 'Perfect competition: allocative efficiency (P = MC), productive efficiency (min AC), lower prices, no deadweight loss. But: no dynamic efficiency (no supernormal profit to fund R&D), may not exploit EoS, unrealistic model assumptions. Monopoly: may achieve EoS leading to lower costs/prices, supernormal profit funds innovation (Schumpeter), dynamic efficiency. But: higher prices, lower output, deadweight loss, X-inefficiency, restricted choice. Evaluation: depends on market characteristics; natural monopolies may serve consumers better than fragmented competition; contestability matters more than market structure; regulated monopoly may combine benefits of both.' },
      { q: 'Evaluate the effectiveness of the Competition and Markets Authority (CMA) in promoting competitive markets.', marks: 6, markScheme: 'CMA powers: investigate mergers, penalise anti-competitive behaviour, enforce consumer protection. Successes: blocked harmful mergers, fined cartels, improved consumer outcomes in some markets. Limitations: tacit collusion is hard to detect and prove; firms have resources to challenge rulings; global mergers may be beyond UK jurisdiction; political pressure may influence decisions; digital markets pose new challenges. Evaluation: CMA plays an important role but cannot eliminate all anti-competitive behaviour; effectiveness depends on resources, powers, and ability to keep pace with rapidly changing markets.' },
      { q: 'Explain the difference between productive and allocative efficiency.', marks: 3, markScheme: 'Productive efficiency occurs when a firm produces at the lowest point on its average cost curve (minimum AC) (1 mark). Allocative efficiency occurs when price equals marginal cost (P = MC), meaning resources are allocated to reflect consumer preferences (1 mark). A market can be productively efficient without being allocatively efficient, e.g., a monopolist at minimum AC but charging P > MC (1 mark).' },
      { q: 'Explain how game theory helps explain why cartels tend to break down.', marks: 4, markScheme: 'Cartels agree to restrict output and raise prices to maximise joint profits (1 mark). However, each member has an incentive to cheat by secretly increasing output at the high cartel price (prisoner\'s dilemma) (1 mark). If one firm cheats while others comply, the cheater gains significantly higher individual profit (1 mark). Because all firms face this incentive, cheating is the dominant strategy, and the cartel tends to collapse over time (1 mark).' },
      { q: 'State one characteristic of an oligopolistic market.', marks: 1, markScheme: 'A few large firms dominate the market / high concentration ratio / interdependence between firms / significant barriers to entry / non-price competition (any one for 1 mark).' },
      { q: 'State what is meant by a concentration ratio.', marks: 1, markScheme: 'The combined market share of the largest firms in an industry, e.g., a 5-firm concentration ratio is the percentage of total market sales held by the five largest firms (1 mark).' },
      { q: 'Define the term monopoly power.', marks: 2, markScheme: 'Monopoly power is the ability of a firm to set prices above the competitive level (1 mark) due to a lack of close substitutes and/or high barriers to entry in the market (1 mark).' },
      { q: 'Define the term contestable market.', marks: 2, markScheme: 'A contestable market is one where there is freedom of entry and exit with low sunk costs (1 mark), meaning potential competition from new entrants constrains the behaviour of existing firms even if the market is concentrated (1 mark).' },
      { q: 'Draw a diagram showing the deadweight welfare loss caused by a monopolist compared to a competitive market.', marks: 4, diagram: true, markScheme: 'Diagram with MC (supply) and demand (AR) curves, and MR curve below AR (1 mark). Competitive output where MC = AR and monopoly output where MC = MR clearly marked (1 mark). Monopoly price higher and output lower than the competitive level (1 mark). Deadweight welfare loss triangle shaded between the demand curve and MC curve from monopoly to competitive output (1 mark).' },
      { q: 'Explain why a perfectly competitive firm is both allocatively and productively efficient in long-run equilibrium.', marks: 4, markScheme: 'In long-run equilibrium, the firm produces where P = MC, satisfying the condition for allocative efficiency (1 mark). This means resources are allocated in line with consumer preferences (1 mark). The firm also produces at the minimum point of the LRAC curve, satisfying the condition for productive efficiency (1 mark). Competition drives firms to minimise costs; those that do not are undercut and exit the market (1 mark).' },
      { q: 'Explain how predatory pricing can be used as an anti-competitive strategy.', marks: 3, markScheme: 'Predatory pricing involves a firm temporarily setting prices below average variable cost to force competitors out of the market (1 mark). The firm absorbs short-run losses, funded by profits from other markets or financial reserves (1 mark). Once competitors have exited, the firm raises prices and uses its enhanced market power to recoup losses and earn supernormal profit (1 mark).' },
      { q: 'Explain the concept of a Nash equilibrium using an example from oligopoly.', marks: 3, markScheme: 'A Nash equilibrium occurs when each firm is choosing its best strategy given the strategies chosen by all other firms (1 mark). No firm has an incentive to unilaterally change its strategy because doing so would worsen its outcome (1 mark). Example: in the prisoner\'s dilemma, both firms choosing to advertise is a Nash equilibrium, even though mutual non-advertising would yield higher joint profits (1 mark).' },
      { q: 'Explain how brand loyalty acts as a barrier to entry in monopolistic competition.', marks: 3, markScheme: 'Established firms invest heavily in advertising and brand development, creating strong consumer attachment (1 mark). New entrants must spend significantly on marketing to persuade consumers to switch, raising their costs of entry (1 mark). This makes it harder for new firms to gain market share even though there are no formal barriers like patents or licences (1 mark).' },
      { q: 'Explain the difference between first-degree, second-degree, and third-degree price discrimination.', marks: 4, markScheme: 'First-degree (perfect): each consumer is charged their maximum willingness to pay, extracting all consumer surplus (1 mark). Second-degree: different prices charged based on the quantity purchased, e.g., bulk discounts or block tariffs (1 mark). Third-degree: different prices charged to identifiable groups with different PED, e.g., student discounts, peak/off-peak pricing (1 mark). Third-degree is the most common form as firms can separate markets and prevent resale between groups (1 mark).' },
      { q: 'Explain two ways in which monopoly may benefit consumers.', marks: 4, markScheme: 'Dynamic efficiency: monopoly supernormal profits can fund research and development, leading to innovation and new products that benefit consumers over time (Schumpeter argument) (1 mark)(1 mark). Economies of scale: a single large firm may achieve lower average costs than many small firms, potentially passing savings on as lower prices, especially in natural monopoly industries (1 mark)(1 mark).' },
      { q: 'Explain the role of sunk costs in determining market contestability.', marks: 3, markScheme: 'Sunk costs are costs that cannot be recovered on exit from a market, e.g., specialised equipment, advertising expenditure (1 mark). High sunk costs deter entry because potential entrants risk large losses if the venture fails (1 mark). Low sunk costs make hit-and-run entry viable, increasing contestability and forcing incumbents to behave competitively (1 mark).' },
      { q: 'Explain why firms in monopolistic competition face a downward-sloping demand curve.', marks: 3, markScheme: 'Each firm sells a differentiated product that is not a perfect substitute for competitors\' products (1 mark). This gives the firm some degree of market power; it can raise price without losing all customers (1 mark). However, the demand curve is relatively elastic because many close substitutes exist, so large price increases cause significant customer switching (1 mark).' },
      { q: 'Explain how limit pricing can deter potential entrants to a market.', marks: 3, markScheme: 'Limit pricing involves an incumbent firm setting a price low enough to make entry unprofitable for potential competitors (1 mark). The price is set just below the level at which a new entrant could cover its average costs including normal profit (1 mark). While the incumbent sacrifices some short-run profit, it maintains its market position and avoids the costs of competitive rivalry in the long run (1 mark).' },
      { q: 'Evaluate whether monopolistic competition is good for consumers.', marks: 6, markScheme: 'Benefits: product differentiation gives consumers wide choice and variety; low barriers to entry keep the market competitive; firms innovate to differentiate, improving quality; only normal profit in long run keeps prices reasonable. Drawbacks: not productively efficient (does not produce at minimum AC); not allocatively efficient (P > MC); advertising costs may be wasteful and raise prices; excess capacity means resources are not fully utilised. Evaluation: consumers benefit from variety and competition but pay slightly higher prices than in perfect competition; the trade-off between variety and efficiency is generally considered acceptable in most real-world markets.' },
      { q: 'Evaluate whether oligopoly leads to better outcomes for consumers than monopoly.', marks: 6, markScheme: 'Better outcomes: some competition exists even if limited; non-price competition (quality, innovation) benefits consumers; threat of competitive behaviour constrains pricing; consumers benefit from advertising and loyalty schemes. Worse outcomes: collusion (tacit or overt) can mimic monopoly outcomes; interdependence may lead to price rigidity; high barriers to entry still limit competition; firms may compete on wasteful advertising rather than price. Evaluation: depends on whether competition or collusion dominates; contestability, regulation, and threat of entry matter more than the number of firms; well-regulated oligopolies may serve consumers better than unregulated monopolies.' },
      { q: 'Explain what is meant by dynamic efficiency and why it may be associated with monopoly.', marks: 3, markScheme: 'Dynamic efficiency refers to improvements in products and production processes over time through innovation and technological progress (1 mark). Monopolies earn supernormal profit which can be reinvested in research and development (1 mark). Schumpeter argued that the prospect of monopoly profits provides the incentive and the funding for innovation, making monopoly dynamically efficient even if statically inefficient (1 mark).' },
      { q: 'Explain, using a diagram, how third-degree price discrimination increases a firm\'s profit compared to charging a single price.', marks: 4, diagram: true, markScheme: 'Two diagrams showing markets with different PED (e.g., adults and students) (1 mark). Higher price charged in the market with more inelastic demand and lower price in the market with more elastic demand (1 mark). Each market has its own MR curve; the firm equates MC = MR in each market separately (1 mark). Total profit is higher than charging a single price because the firm extracts more consumer surplus from each group (1 mark).' },
      { q: 'Explain two reasons why the market for supermarkets in the UK may be considered an oligopoly.', marks: 4, markScheme: 'High concentration ratio: a few large firms (Tesco, Sainsbury\'s, Asda, Morrisons) hold a large share of total grocery sales (1 mark). This gives these firms significant market power and influence over prices and suppliers (1 mark). Interdependence: pricing decisions by one supermarket (e.g., a price war) directly affect rivals, and firms closely monitor and respond to competitors\' strategies (1 mark). Significant barriers to entry exist including large capital requirements, established supply chains, and brand loyalty (1 mark).' },
      { q: 'Explain the concept of a dominant strategy in game theory.', marks: 2, markScheme: 'A dominant strategy is a strategy that gives a player the best payoff regardless of what the other player(s) choose to do (1 mark). If both players have a dominant strategy, the outcome where both play their dominant strategy is the Nash equilibrium (1 mark).' }
    ]
  },
  '3.1.5': {
    name: 'Market Failure & Government Intervention',
    questions: [
      { q: 'State what is meant by a positive externality.', marks: 1, markScheme: 'A benefit to a third party not directly involved in the production or consumption of a good/service (1 mark).' },
      { q: 'State one example of a demerit good.', marks: 1, markScheme: 'Tobacco / alcohol / illegal drugs / gambling / sugary drinks (any valid demerit good for 1 mark).' },
      { q: 'Define the term public good.', marks: 2, markScheme: 'A public good is one that is non-excludable (impossible to prevent non-payers from consuming it) (1 mark) and non-rival (one person consuming it does not reduce availability for others) (1 mark).' },
      { q: 'State the formula for social cost.', marks: 1, markScheme: 'Social cost = Private cost + External cost (1 mark).' },
      { q: 'Draw a diagram showing a negative production externality. Label the welfare loss.', marks: 4, diagram: true, markScheme: 'Diagram with MSC above MPC (supply) and MSB = MPB (demand) (1 mark). Free market output where MPC = MPB identified (1 mark). Socially optimal output where MSC = MSB identified (1 mark). Welfare loss triangle between MSC, MPC from social optimum to free market output shaded and labelled (1 mark).' },
      { q: 'Draw a diagram showing a positive consumption externality. Label the under-provision.', marks: 4, diagram: true, markScheme: 'Diagram with MSB above MPB (demand) and MSC = MPC (supply) (1 mark). Free market output where MPC = MPB identified (1 mark). Socially optimal output where MSC = MSB identified (1 mark). Under-provision shown as the gap between free market and socially optimal output (1 mark).' },
      { q: 'Explain how an indirect tax can be used to correct a negative production externality.', marks: 3, markScheme: 'A negative production externality means MPC < MSC so the free market overproduces (1 mark). A tax equal to the marginal external cost at the social optimum shifts MPC up to MSC (1 mark). This internalises the externality, raising costs to producers and reducing output towards the socially optimal level (1 mark).' },
      { q: 'Explain two reasons why the free market under-provides public goods.', marks: 4, markScheme: 'Non-excludability: firms cannot charge for the good because non-payers cannot be prevented from benefiting (free rider problem) (1 mark). Therefore firms cannot earn revenue and have no incentive to produce the good (1 mark). Non-rivalry: the marginal cost of an extra user is zero so it is inefficient to charge a price, but firms need revenue to cover production costs (1 mark). The combination means private markets fail to provide socially desirable public goods like national defence and street lighting (1 mark).' },
      { q: 'Explain one advantage and one disadvantage of using regulation to address market failure.', marks: 4, markScheme: 'Advantage: regulation can set clear enforceable standards (e.g., emissions limits, safety requirements) that directly control harmful behaviour (1 mark). This provides certainty about outcomes and can be targeted at specific problems (1 mark). Disadvantage: regulation imposes compliance costs on businesses which may be passed on to consumers as higher prices (1 mark). It may also lead to regulatory capture where the regulator acts in the interest of the industry rather than society (1 mark).' },
      { q: 'Explain how tradeable pollution permits work and why they are considered efficient.', marks: 4, markScheme: 'Government sets a total cap on emissions and issues permits equal to this cap (1 mark). Firms that can reduce pollution cheaply sell their unused permits; firms facing high abatement costs buy permits (1 mark). Trading ensures pollution reductions occur where they are cheapest, minimising total cost to the economy (1 mark). The cap guarantees a specific environmental outcome while the market determines the most efficient allocation (1 mark).' },
      { q: 'Explain how asymmetric information leads to market failure in the used car market.', marks: 3, markScheme: 'Sellers know the true quality of their car but buyers do not (information asymmetry) (1 mark). Buyers offer a price reflecting average expected quality, which is too low for good cars but acceptable for poor ones (lemons) (1 mark). Good cars are withdrawn from the market (adverse selection), leaving mainly poor-quality cars and reducing market efficiency (Akerlof\'s model) (1 mark).' },
      { q: 'Explain how a nudge can address information failure in pension saving.', marks: 3, markScheme: 'Many workers under-save for retirement due to present bias and inertia (information failure/bounded rationality) (1 mark). Auto-enrolment nudges workers into pension schemes by making saving the default option (1 mark). Workers can opt out but most do not, significantly increasing pension participation without removing choice (libertarian paternalism) (1 mark).' },
      { q: 'Explain two possible causes of government failure.', marks: 4, markScheme: 'Unintended consequences: government policies may have effects that were not anticipated, worsening the situation (e.g., rent controls creating housing shortages) (1 mark)(1 mark). Regulatory capture: regulators may be influenced by the industries they are supposed to regulate, leading to policies that benefit producers rather than consumers (1 mark)(1 mark). Other valid: information gaps, political short-termism, bureaucratic inefficiency, distortion of incentives.' },
      { q: 'Explain why healthcare is considered a merit good.', marks: 3, markScheme: 'Individuals may underestimate the long-term benefits of preventive healthcare due to information failure (1 mark). Healthcare generates positive externalities: a healthy workforce is more productive and reduces infection spread (1 mark). Left to the free market, healthcare would be under-consumed relative to the socially optimal level, justifying government intervention (1 mark).' },
      { q: 'Explain the concept of moral hazard using an example from insurance.', marks: 3, markScheme: 'Moral hazard occurs when one party changes their behaviour after entering a contract because they are protected from the consequences (1 mark). Example: a fully insured driver may take less care because they know the insurance company will cover any damage (1 mark). This increases the probability of the negative outcome occurring, raising costs for insurers and potentially the insurance market as a whole (1 mark).' },
      { q: 'Evaluate the effectiveness of a sugar tax in reducing obesity.', marks: 6, markScheme: 'How it works: tax increases price of sugary drinks, reducing consumption (if PED allows). Evidence: UK Soft Drinks Industry Levy led to reformulation and some demand reduction. Strengths: targets a specific contributor to obesity; generates revenue for health spending; nudges producers to reduce sugar content. Weaknesses: demand may be price inelastic for habitual consumers; consumers may switch to other unhealthy products not taxed; regressive (hits lower-income groups harder); obesity has many causes beyond sugar. Evaluation: a useful part of a wider strategy but insufficient alone; needs combining with education, advertising restrictions, and promoting physical activity.' },
      { q: 'Evaluate the view that the government should always intervene to correct externalities.', marks: 6, markScheme: 'Case for: externalities cause deadweight loss and misallocation; taxes and subsidies can internalise costs/benefits; regulation protects third parties; public goods need state provision. Case against: government failure may make things worse (unintended consequences, regulatory capture); difficulty measuring marginal external costs accurately; Coase theorem suggests private bargaining can work with clear property rights and low transaction costs; political motivations may distort policy. Evaluation: intervention is justified when market failure is significant and measurable, but the method and scale must be carefully designed; cost-benefit analysis should guide decisions; the risk of government failure must be weighed against the cost of inaction.' },
      { q: 'Explain the difference between a merit good and a public good.', marks: 3, markScheme: 'A merit good is excludable and rival but is under-consumed due to information failure or positive externalities (e.g., education) (1 mark). A public good is non-excludable and non-rival, leading to the free rider problem and under-provision by markets (e.g., national defence) (1 mark). Merit goods can be provided by markets but at sub-optimal levels; public goods typically cannot be provided by markets at all (1 mark).' },
      { q: 'Explain how the Coase theorem suggests externalities can be resolved without government intervention.', marks: 4, markScheme: 'If property rights are clearly defined and enforceable, the affected parties can negotiate a solution (1 mark). The party causing the externality can compensate the affected party, or vice versa (1 mark). The outcome will be efficient regardless of who holds the property rights (as long as transaction costs are low) (1 mark). Limitation: works best with few parties and low transaction costs; large-scale externalities like air pollution involve too many parties for negotiation to be practical (1 mark).' },
      { q: 'Explain why cost-benefit analysis may not always lead to the correct decision on public investment.', marks: 4, markScheme: 'Difficulty valuing external costs and benefits in monetary terms (e.g., how to value loss of biodiversity or community displacement) (1 mark). Choice of discount rate for future costs and benefits is subjective and significantly affects outcomes (1 mark). Political influence may bias estimates to favour or block projects (1 mark). Uncertainty about long-term effects means estimates may prove inaccurate (1 mark).' },
      { q: 'State what is meant by a negative externality of consumption.', marks: 1, markScheme: 'A cost imposed on a third party as a result of the consumption of a good or service, e.g., passive smoking from cigarette consumption (1 mark).' },
      { q: 'State one example of a merit good.', marks: 1, markScheme: 'Education / healthcare / vaccinations / museums / libraries (any valid merit good for 1 mark).' },
      { q: 'Define the term market failure.', marks: 2, markScheme: 'Market failure occurs when the free market mechanism leads to a misallocation of resources (1 mark), resulting in a loss of economic and social welfare compared to the socially optimal outcome (1 mark).' },
      { q: 'Define the term government failure.', marks: 2, markScheme: 'Government failure occurs when government intervention in a market leads to a net welfare loss (1 mark), making the allocation of resources worse than it would have been without the intervention (1 mark).' },
      { q: 'Draw a diagram showing a negative consumption externality. Label the welfare loss from overconsumption.', marks: 4, diagram: true, markScheme: 'Diagram with MSB below MPB (demand) and MSC = MPC (supply) (1 mark). Free market output where MPC = MPB identified (1 mark). Socially optimal output where MSC = MSB identified (1 mark). Welfare loss triangle between MPB and MSB from social optimum to free market output shaded (1 mark).' },
      { q: 'Explain how a subsidy can be used to correct under-consumption of a merit good.', marks: 3, markScheme: 'A merit good is under-consumed because individuals undervalue its benefits due to information failure (1 mark). A subsidy reduces the price to consumers, increasing consumption towards the socially optimal level (1 mark). The subsidy effectively bridges the gap between MPB and MSB, internalising the positive externality (1 mark).' },
      { q: 'Explain why common access resources may be subject to market failure.', marks: 3, markScheme: 'Common access resources (e.g., fish stocks, clean air) are rival but non-excludable (1 mark). Because no one can be excluded, users have no incentive to limit their use, leading to overexploitation (tragedy of the commons) (1 mark). Without property rights or regulation, the resource is depleted faster than it can regenerate, resulting in market failure (1 mark).' },
      { q: 'Explain how information failure leads to the overconsumption of demerit goods.', marks: 3, markScheme: 'Consumers of demerit goods underestimate the private costs (e.g., health risks of smoking) due to imperfect information (1 mark). They also ignore the negative externalities their consumption imposes on others (1 mark). As a result, consumption exceeds the socially optimal level, and MPB > MSB at the market quantity (1 mark).' },
      { q: 'Explain two methods the government could use to reduce carbon emissions.', marks: 4, markScheme: 'Carbon tax: placing a tax on each unit of CO2 emitted raises the private cost of polluting activities, incentivising firms to reduce emissions and invest in cleaner technology (1 mark)(1 mark). Cap-and-trade system: the government sets a total emissions cap and issues tradeable permits; firms that reduce emissions cheaply sell permits to those with higher abatement costs, achieving the target efficiently (1 mark)(1 mark).' },
      { q: 'Explain why the free rider problem makes it difficult for the private sector to provide street lighting.', marks: 3, markScheme: 'Street lighting is non-excludable: once provided, anyone can benefit whether they have paid or not (1 mark). Rational individuals will not voluntarily pay because they can free ride on others\' contributions (1 mark). Since firms cannot charge users and recover costs, they have no incentive to provide street lighting, leading to market failure and the need for government provision (1 mark).' },
      { q: 'Explain the concept of quasi-public goods using an example.', marks: 3, markScheme: 'Quasi-public goods possess some but not all characteristics of pure public goods (1 mark). For example, roads are non-excludable in general use but become excludable with toll charges, and can become rival during congestion (1 mark). They could be provided by the private sector but are often provided or subsidised by the government because market provision would be sub-optimal (1 mark).' },
      { q: 'Explain how extending property rights can help resolve environmental externalities.', marks: 3, markScheme: 'If property rights over a resource (e.g., a river) are clearly defined and legally enforceable, the owner can charge for its use or seek compensation for damage (1 mark). This internalises the externality by making polluters face the cost of their actions (1 mark). Linked to the Coase theorem, this can lead to efficient outcomes through negotiation without government regulation (1 mark).' },
      { q: 'Explain how minimum unit pricing for alcohol aims to reduce negative externalities.', marks: 3, markScheme: 'Minimum unit pricing sets a floor price per unit of alcohol, targeting cheap high-strength drinks most associated with harmful drinking (1 mark). By raising the price of the cheapest alcohol, it reduces consumption among heavy drinkers who tend to be most price-sensitive (1 mark). Lower consumption reduces negative externalities such as alcohol-related violence, health costs, and lost productivity (1 mark).' },
      { q: 'Explain one reason why banning a product entirely may lead to government failure.', marks: 3, markScheme: 'A ban removes legal supply but may not eliminate demand, driving consumers to illegal black markets (1 mark). Black market products are unregulated, potentially more dangerous, and generate criminal activity (1 mark). The government loses tax revenue and spends resources on enforcement, while the ban may cause more harm than the original market failure it was intended to correct (1 mark).' },
      { q: 'Evaluate the effectiveness of tradeable pollution permits compared to carbon taxes in reducing emissions.', marks: 6, markScheme: 'Permits: guarantee a specific quantity of emissions (environmental certainty); allow market to find cheapest reductions; firms have flexibility. But: setting the cap requires information; price volatility may discourage investment; lobbying for free permits reduces effectiveness. Carbon tax: provides price certainty for businesses; generates revenue for green investment; simpler to administer. But: does not guarantee a specific emissions reduction; politically difficult to set at the right level; regressive if it raises energy prices for the poor. Evaluation: both have merits; permits offer quantity certainty while taxes offer price certainty; many economists advocate combining both approaches; effectiveness depends on design, enforcement, and international cooperation.' },
      { q: 'Evaluate the view that direct provision of public goods by the government is always preferable to private provision.', marks: 6, markScheme: 'For government provision: overcomes the free rider problem; ensures universal access; can be funded through taxation; no profit motive ensures focus on social benefit. Against: government provision may be inefficient (X-inefficiency, bureaucracy); political priorities may distort allocation; no market signals to indicate optimal quantity; private-public partnerships may combine efficiency with access. Evaluation: pure public goods like national defence require government provision, but many quasi-public goods (toll roads, parks) can be effectively provided through public-private partnerships; the optimal arrangement depends on the specific good and institutional context.' },
      { q: 'Explain the difference between a specific tax and an ad valorem tax on a good.', marks: 3, markScheme: 'A specific tax is a fixed amount per unit of a good sold regardless of its price, e.g., 10p per litre of fuel (1 mark). An ad valorem tax is a percentage of the price of the good, e.g., 20% VAT (1 mark). On a diagram, a specific tax shifts the supply curve upward by a constant amount, while an ad valorem tax causes the supply curve to pivot, with the gap widening at higher prices (1 mark).' },
      { q: 'Explain why an indirect tax on a good with inelastic demand generates more government revenue but causes less reduction in quantity consumed.', marks: 3, markScheme: 'When demand is price inelastic, consumers are unresponsive to price changes (few substitutes, necessity) (1 mark). A tax raises the price but quantity demanded falls only slightly, so the tax base remains large and revenue is high (1 mark). However, because quantity falls little, the tax is less effective at reducing consumption of the harmful good, which may limit its corrective purpose (1 mark).' },
      { q: 'Explain how adverse selection can cause market failure in health insurance markets.', marks: 3, markScheme: 'Adverse selection arises because individuals know more about their own health risks than insurers (asymmetric information) (1 mark). High-risk individuals are more likely to purchase insurance while low-risk individuals may opt out if premiums are too high (1 mark). This raises the average risk in the pool, pushing premiums higher and potentially causing market collapse as only the sickest remain insured (1 mark).' },
      { q: 'Explain why a congestion charge can be considered a market-based solution to a negative externality.', marks: 3, markScheme: 'Traffic congestion imposes negative externalities on third parties including pollution, delays, and lost productivity (1 mark). A congestion charge forces drivers to pay the external cost of their journeys, internalising the externality and bringing private costs closer to social costs (1 mark). This reduces the volume of traffic towards the socially optimal level through the price mechanism rather than through direct regulation (1 mark).' }
    ]
  },
  '3.2.1': {
    name: 'Measurement of Macroeconomic Performance',
    questions: [
      { q: 'State what GDP measures.', marks: 1, markScheme: 'The total value of goods and services produced within an economy over a given time period (usually a year) (1 mark).' },
      { q: 'State one component of the current account of the balance of payments.', marks: 1, markScheme: 'Trade in goods / trade in services / primary income / secondary income (transfers) (any one for 1 mark).' },
      { q: 'Define the term real GDP.', marks: 2, markScheme: 'Real GDP is the total output of an economy (1 mark) adjusted for changes in the price level/measured at constant prices to remove the effect of inflation (1 mark).' },
      { q: 'Define the term structural unemployment.', marks: 2, markScheme: 'Structural unemployment occurs when there is a mismatch between the skills workers have and the skills demanded by employers (1 mark), often caused by long-term changes in the structure of the economy such as deindustrialisation (1 mark).' },
      { q: 'Explain the difference between the claimant count and the Labour Force Survey as measures of unemployment.', marks: 4, markScheme: 'The claimant count measures those receiving unemployment-related benefits (Jobseekers Allowance/Universal Credit) (1 mark). It may understate unemployment as some unemployed people are not eligible or do not claim (1 mark). The LFS uses the ILO definition, surveying households to find those without work, seeking work, and available to start (1 mark). It is more comprehensive but is based on a sample and may have sampling errors (1 mark).' },
      { q: 'Explain two limitations of using CPI to measure changes in the cost of living.', marks: 4, markScheme: 'The fixed basket may not reflect individual spending patterns; different households experience different rates of inflation (1 mark)(1 mark). Quality improvements in goods are hard to account for; a rising index may partly reflect better products rather than purely higher costs (1 mark)(1 mark). Other valid: new products take time to enter the basket, substitution bias, does not include housing costs (owner-occupied).' },
      { q: 'Explain the difference between demand-pull and cost-push inflation using AD/AS diagrams.', marks: 6, diagram: true, markScheme: 'Demand-pull: AD shifts right along SRAS, causing price level to rise and real output to increase (1 mark). Diagram showing rightward AD shift with higher price and output (1 mark). Caused by increases in C, I, G, or X-M (1 mark). Cost-push: SRAS shifts left along AD, causing price level to rise and real output to fall (1 mark). Diagram showing leftward SRAS shift with higher price and lower output (1 mark). Caused by rising costs of production such as wages, raw materials, or energy (1 mark).' },
      { q: 'Explain why GDP per capita may be a better indicator of living standards than total GDP.', marks: 3, markScheme: 'Total GDP may grow simply because of population growth rather than increased prosperity per person (1 mark). GDP per capita divides total output by population, giving a better measure of average income/output per person (1 mark). However, it still does not account for income distribution, so high GDP per capita may coexist with significant poverty (1 mark).' },
      { q: 'Explain two possible causes of a current account deficit.', marks: 4, markScheme: 'Strong domestic growth: rising incomes lead to increased demand for imports of goods and services (1 mark). This widens the trade deficit if export growth does not keep pace (1 mark). Overvalued exchange rate: a strong currency makes exports relatively expensive and imports relatively cheap (1 mark). This reduces export competitiveness and encourages import substitution (1 mark).' },
      { q: 'Explain the difference between a positive and negative output gap.', marks: 3, markScheme: 'A positive output gap occurs when actual GDP exceeds potential GDP, meaning the economy is operating above its sustainable capacity (1 mark). This creates inflationary pressure as demand outstrips supply (1 mark). A negative output gap occurs when actual GDP is below potential GDP, indicating spare capacity and typically higher unemployment (1 mark).' },
      { q: 'Explain why the informal/shadow economy creates problems for measuring GDP.', marks: 3, markScheme: 'The informal economy includes unreported economic activity (cash-in-hand work, illegal markets) not captured in official statistics (1 mark). This means GDP underestimates actual economic output, potentially significantly in developing countries (1 mark). It makes GDP comparisons between countries with different sizes of informal economies misleading (1 mark).' },
      { q: 'Explain the concept of hysteresis in the context of unemployment.', marks: 3, markScheme: 'Hysteresis means that prolonged unemployment can become self-reinforcing and permanent (1 mark). Workers lose skills, motivation, and become less attractive to employers the longer they are out of work (1 mark). This raises the natural rate of unemployment even after the initial cause (e.g., recession) has passed, as previously cyclical unemployment becomes structural (1 mark).' },
      { q: 'Explain the difference between inflation and deflation and state one cost of each.', marks: 4, markScheme: 'Inflation is a sustained rise in the general price level (1 mark). Cost: erodes purchasing power of those on fixed incomes; creates uncertainty for business planning (1 mark). Deflation is a sustained fall in the general price level (1 mark). Cost: consumers delay purchases expecting further falls, reducing AD; increases real value of debt burdens (1 mark).' },
      { q: 'Explain why PPP-adjusted GDP is preferred for international comparisons.', marks: 3, markScheme: 'Market exchange rates do not reflect differences in the cost of living between countries (1 mark). PPP adjusts GDP to account for what money can actually buy domestically (purchasing power) (1 mark). This gives a more accurate comparison of actual living standards, particularly between developed and developing countries where price levels differ greatly (1 mark).' },
      { q: 'Evaluate whether GDP is a suitable measure for comparing economic welfare between countries.', marks: 6, markScheme: 'Strengths: widely available, standardised methodology allows comparison, captures market economic activity comprehensively. Weaknesses: ignores income distribution (Gini coefficient differences); does not capture non-market activity (subsistence farming in developing countries); fails to account for environmental costs; PPP adjustments are imperfect; does not measure happiness, health, or education. Alternatives: HDI, GNI, happiness indices. Evaluation: GDP is a useful starting point but insufficient alone; should be supplemented with broader indicators to capture true welfare differences between countries.' },
      { q: 'Evaluate the significance of a persistent current account deficit for the UK economy.', marks: 6, markScheme: 'Concerns: indicates potential loss of competitiveness; must be financed by capital inflows (selling assets or borrowing); accumulation of foreign debt creates future servicing obligations; may eventually trigger currency depreciation and imported inflation. Mitigating factors: UK deficit partly reflects strong economy attracting investment; capital inflows may fund productive investment; floating exchange rate provides automatic adjustment mechanism; deficit may be sustainable if economy grows. Evaluation: significance depends on causes (consumption vs investment), size relative to GDP, ease of financing, and whether it is a symptom of declining competitiveness or healthy economic growth.' },
      { q: 'Explain what the Gini coefficient measures and how it is interpreted.', marks: 3, markScheme: 'The Gini coefficient measures income (or wealth) inequality within a country (1 mark). It ranges from 0 (perfect equality, everyone has the same income) to 1 (perfect inequality, one person has all the income) (1 mark). A higher coefficient indicates greater inequality; it is derived from the Lorenz curve showing the cumulative share of income against cumulative share of population (1 mark).' },
      { q: 'Explain two costs of unemployment to the economy.', marks: 4, markScheme: 'Lost output: the economy operates below its productive potential (inside the PPF), representing a waste of resources (1 mark). This reduces GDP and tax revenue while increasing benefit payments (1 mark). Social costs: prolonged unemployment can lead to poverty, health problems, increased crime, and social exclusion (1 mark). These impose additional costs on public services and reduce overall wellbeing (1 mark).' },
      { q: 'Explain the J-curve effect following a depreciation of the exchange rate.', marks: 4, markScheme: 'Immediately after depreciation, the trade balance worsens because import prices rise but volumes have not yet adjusted (contracts are fixed) (1 mark). Exports are cheaper in foreign currency but increased demand takes time to materialise (1 mark). Over time, if the Marshall-Lerner condition is met (sum of PED for exports and imports > 1), volumes adjust and the trade balance improves (1 mark). The path of the trade balance over time resembles the letter J (1 mark).' },
      { q: 'Explain why the RPI tends to give a higher inflation figure than CPI.', marks: 3, markScheme: 'RPI includes mortgage interest payments which are excluded from CPI (1 mark). RPI uses the arithmetic mean for averaging prices while CPI uses the geometric mean, which gives a lower figure (1 mark). Different coverage and weighting means the two indices can diverge significantly, especially when interest rates change (1 mark).' },
      { q: 'State one cause of frictional unemployment.', marks: 1, markScheme: 'Workers moving between jobs / time spent searching for a new job / graduates entering the labour market / seasonal changes in employment (any one for 1 mark).' },
      { q: 'State the difference between nominal and real values.', marks: 1, markScheme: 'Nominal values are measured at current/money prices, while real values are adjusted for inflation to reflect actual purchasing power (1 mark).' },
      { q: 'Define the term balance of payments.', marks: 2, markScheme: 'The balance of payments is a record of all financial transactions between a country and the rest of the world (1 mark) over a given time period, including the current account, capital account, and financial account (1 mark).' },
      { q: 'Define the term cyclical unemployment.', marks: 2, markScheme: 'Cyclical (demand-deficient) unemployment is caused by a fall in aggregate demand during an economic downturn (1 mark). Firms reduce output and lay off workers because there is insufficient demand for goods and services (1 mark).' },
      { q: 'Explain the three methods of measuring GDP and why they should give the same result.', marks: 4, markScheme: 'Output method: measures the total value of goods and services produced in each sector of the economy (1 mark). Income method: measures the total incomes earned by factors of production (wages, profits, rent, interest) (1 mark). Expenditure method: measures total spending on goods and services (C + I + G + X - M) (1 mark). They should give the same result because every pound of output generates a pound of income and a pound of expenditure in the circular flow (1 mark).' },
      { q: 'Explain two costs of inflation to an economy.', marks: 4, markScheme: 'Menu costs: firms must frequently update prices in catalogues, displays, and IT systems, which is costly and time-consuming (1 mark). These administrative costs divert resources from productive activity (1 mark). Shoe leather costs: individuals and firms make more frequent trips to banks to minimise cash holdings losing value, wasting time and effort (1 mark). Additionally, international competitiveness falls if domestic inflation exceeds that of trading partners, reducing exports (1 mark).' },
      { q: 'Using a diagram, explain how wage-push inflation can occur.', marks: 4, diagram: true, markScheme: 'AD/AS diagram with SRAS shifting to the left (1 mark). Trade unions or labour market tightness pushes up wages above productivity growth (1 mark). Higher wage costs increase firms\' production costs, shifting SRAS left (1 mark). The result is a higher price level and potentially lower real output (cost-push inflation) (1 mark).' },
      { q: 'Explain why the unemployment rate may understate the true level of joblessness.', marks: 3, markScheme: 'Discouraged workers who have stopped actively looking for work are not counted as unemployed in official statistics (1 mark). Part-time workers who want full-time work (underemployed) are counted as employed even though they are not fully utilised (1 mark). Those on government training schemes or in the informal economy may also be excluded, masking the true extent of labour market slack (1 mark).' },
      { q: 'Explain how a depreciation of the exchange rate may lead to inflation.', marks: 3, markScheme: 'A depreciation makes imports more expensive in domestic currency (1 mark). Higher import prices increase costs for firms using imported raw materials and components, causing cost-push inflation (1 mark). The cost of imported consumer goods also rises directly, increasing the CPI and reducing real purchasing power (1 mark).' },
      { q: 'Explain the difference between the current account and the financial account of the balance of payments.', marks: 3, markScheme: 'The current account records trade in goods and services, primary income (investment income), and secondary income (transfers) (1 mark). The financial account records capital flows: foreign direct investment, portfolio investment, and reserve assets (1 mark). A current account deficit must be matched by a financial account surplus (capital inflow) and vice versa, so the balance of payments always balances (1 mark).' },
      { q: 'Explain the concept of the natural rate of unemployment.', marks: 3, markScheme: 'The natural rate is the level of unemployment that exists when the labour market is in equilibrium and there is no cyclical unemployment (1 mark). It includes frictional and structural unemployment that persist even when the economy is at full capacity (1 mark). According to monetarists, attempting to push unemployment below this rate through demand management will only cause accelerating inflation (1 mark).' },
      { q: 'Explain why GNI (Gross National Income) may differ significantly from GDP for some countries.', marks: 3, markScheme: 'GNI includes income earned by domestic residents from overseas investments but excludes income earned by foreign nationals within the country (1 mark). Countries with large outward investment (e.g., UK, Japan) may have GNI higher than GDP because of repatriated profits and interest (1 mark). Countries with significant foreign-owned businesses (e.g., Ireland) may have GDP much higher than GNI as profits flow abroad (1 mark).' },
      { q: 'Explain two limitations of using GDP to measure living standards within a country.', marks: 4, markScheme: 'GDP does not account for income distribution; a high GDP per capita may coexist with significant poverty if wealth is concentrated (1 mark). The Gini coefficient or other inequality measures are needed alongside GDP (1 mark). GDP does not measure non-market activities such as household work, volunteer work, or leisure time, which all contribute to wellbeing (1 mark). Environmental degradation counts as positive GDP (clean-up spending) even though it reduces quality of life (1 mark).' },
      { q: 'Explain what is meant by the terms of trade and how they are calculated.', marks: 3, markScheme: 'The terms of trade measure the ratio of export prices to import prices (1 mark). Formula: index of export prices / index of import prices x 100 (1 mark). An improvement in the terms of trade means export prices rise relative to import prices, so fewer exports are needed to pay for a given volume of imports (1 mark).' },
      { q: 'Evaluate the view that low unemployment should always be the government\'s primary macroeconomic objective.', marks: 6, markScheme: 'For: unemployment wastes resources and creates social costs (poverty, crime, ill health); reducing unemployment raises output, tax revenue, and reduces benefit spending; politically important. Against: pursuing very low unemployment may cause demand-pull inflation (Phillips curve trade-off); structural unemployment may require supply-side policies that take years; focusing on employment alone ignores other objectives (inflation, growth, trade balance). Evaluation: full employment is important but must be balanced against other objectives; the natural rate concept suggests a limit to how far unemployment can be reduced without inflation; the priority depends on current economic conditions and existing levels of unemployment.' },
      { q: 'Evaluate whether the Human Development Index (HDI) is a better measure of development than GDP per capita.', marks: 6, markScheme: 'HDI advantages: combines income with health (life expectancy) and education (mean/expected years of schooling); captures broader aspects of human welfare; allows comparison of development beyond just economic output. HDI limitations: still uses GDP per capita (with its limitations); does not capture inequality (though IHDI does); ignores political freedoms, environmental quality, and personal security; data quality varies. GDP per capita strengths: widely available, easily comparable, captures market economic activity comprehensively. Evaluation: HDI provides a richer picture than GDP alone but is still incomplete; ideally, multiple indicators should be used together to assess development, including measures of inequality, sustainability, and freedom.' },
      { q: 'Explain how seasonal unemployment differs from structural unemployment.', marks: 3, markScheme: 'Seasonal unemployment occurs when demand for labour varies predictably at different times of year, e.g., tourism workers unemployed in winter, agricultural workers between harvests (1 mark). Structural unemployment results from long-term changes in the economy such as deindustrialisation or technological change that make certain skills obsolete (1 mark). Seasonal unemployment is temporary and predictable, while structural unemployment is persistent and requires retraining or relocation to resolve (1 mark).' },
      { q: 'Explain why a country might run a persistent trade deficit despite having strong economic growth.', marks: 3, markScheme: 'Strong growth raises household incomes, increasing demand for imported goods and services (higher marginal propensity to import) (1 mark). Growth may be consumption-driven rather than export-driven, sucking in imports without a corresponding rise in exports (1 mark). An appreciating currency due to capital inflows attracted by the growing economy makes exports expensive and imports cheap, worsening the trade balance (1 mark).' },
      { q: 'Explain what is meant by demand-pull inflation and identify one cause.', marks: 2, markScheme: 'Demand-pull inflation occurs when aggregate demand increases faster than aggregate supply, pulling up the general price level (1 mark). Causes include: excessive growth in consumer spending, expansionary fiscal policy, rapid growth in the money supply, or a fall in the exchange rate boosting net exports (any one for 1 mark).' },
      { q: 'Explain why technological unemployment is classified as structural unemployment.', marks: 2, markScheme: 'Technological unemployment occurs when advances in automation and technology make certain jobs obsolete (1 mark). It is structural because it reflects a long-term mismatch between workers\' existing skills and the new skills demanded by employers, requiring retraining or education to resolve (1 mark).' }
    ]
  },
  '3.2.2': {
    name: 'How the Macroeconomy Works',
    questions: [
      { q: 'State the formula for aggregate demand.', marks: 1, markScheme: 'AD = C + I + G + (X - M) (1 mark).' },
      { q: 'State one injection into the circular flow of income.', marks: 1, markScheme: 'Investment (I) / Government spending (G) / Exports (X) (any one for 1 mark).' },
      { q: 'Define the term marginal propensity to consume.', marks: 2, markScheme: 'The MPC is the proportion/fraction of each additional unit of income (1 mark) that is spent on consumption of goods and services (1 mark).' },
      { q: 'State the multiplier formula in a simple two-sector economy.', marks: 1, markScheme: 'Multiplier = 1 / (1 - MPC) or equivalently 1 / MPS (1 mark).' },
      { q: 'Explain why the AD curve slopes downward from left to right.', marks: 4, markScheme: 'Real balance/wealth effect: a higher price level reduces the real value of wealth, reducing consumption (1 mark). Interest rate effect: higher prices increase demand for money, raising interest rates, which reduces investment and consumption (1 mark). International competitiveness effect: higher domestic prices make exports more expensive and imports cheaper, reducing net exports (1 mark). Therefore a rise in the general price level reduces total planned expenditure (1 mark).' },
      { q: 'Using a diagram, explain how an increase in consumer confidence would affect AD and the macroeconomy.', marks: 4, diagram: true, markScheme: 'AD/AS diagram with AD shifting right (1 mark). Higher consumer confidence increases consumption spending at every price level (1 mark). Short-run effect: real output rises and the price level may increase (1 mark). The extent of price vs output change depends on how close the economy is to full capacity/position on SRAS (1 mark).' },
      { q: 'Explain how the multiplier process works when the government increases spending by 5 billion pounds and the MPC is 0.8.', marks: 4, markScheme: 'Initial injection of 5 billion creates income for households and firms (1 mark). Recipients spend 80% (MPC = 0.8), so 4 billion is spent in the next round, creating further income (1 mark). This continues with each round being 80% of the previous: 5 + 4 + 3.2 + 2.56 + ... (1 mark). The multiplier is 1/(1-0.8) = 5, so the final increase in national income is 5 x 5 = 25 billion pounds (1 mark).' },
      { q: 'Explain why the multiplier is smaller in an open economy with taxation.', marks: 3, markScheme: 'In an open economy, some additional income leaks out through imports (marginal propensity to import) rather than being spent domestically (1 mark). Taxation also withdraws a proportion of each round of income, reducing the amount available for consumption (1 mark). These additional leakages reduce the proportion spent domestically at each stage, making the multiplier smaller: k = 1/(MPS + MPT + MPM) (1 mark).' },
      { q: 'Explain the difference between the classical and Keynesian views of LRAS.', marks: 4, markScheme: 'Classical view: LRAS is vertical at the full employment level of output because in the long run all prices and wages are flexible (1 mark). The economy automatically returns to full employment through market clearing (1 mark). Keynesian view: LRAS has a horizontal section (spare capacity), an upward-sloping section, and becomes vertical only at full capacity (1 mark). This reflects the possibility that the economy can be stuck below full employment due to insufficient AD and sticky wages (1 mark).' },
      { q: 'Explain the accelerator theory of investment.', marks: 3, markScheme: 'The accelerator theory states that the level of investment depends on the rate of change of national income/output rather than its level (1 mark). When national income is growing, firms invest to expand capacity; when growth slows, investment falls sharply (1 mark). This creates a more volatile investment pattern than income changes and can amplify business cycle fluctuations (1 mark).' },
      { q: 'Explain the paradox of thrift.', marks: 3, markScheme: 'If all households simultaneously increase saving (rational for each individual), the MPC falls and consumption drops (1 mark). This reduces aggregate demand, leading to lower output, income, and employment (negative multiplier) (1 mark). Paradoxically, the attempt to save more may reduce total national income so much that actual saving does not increase (or even falls) (1 mark).' },
      { q: 'Using a diagram, explain the effect of an increase in oil prices on the macroeconomy.', marks: 4, diagram: true, markScheme: 'AD/AS diagram with SRAS shifting to the left (1 mark). Rising oil prices increase production costs for firms across the economy (1 mark). The leftward SRAS shift causes the price level to rise and real output to fall (1 mark). This combination of higher prices and lower output is known as stagflation (1 mark).' },
      { q: 'Explain two factors that determine the level of consumption in an economy.', marks: 4, markScheme: 'Disposable income: higher income leads to higher consumption; the Keynesian consumption function shows C rises with Y but by less (MPC < 1) (1 mark)(1 mark). Interest rates: lower rates reduce the reward for saving and the cost of borrowing, encouraging consumption spending especially on durable goods (1 mark)(1 mark). Other valid: wealth/asset prices, consumer confidence, credit availability.' },
      { q: 'Explain how a fall in interest rates affects the exchange rate and net exports.', marks: 4, markScheme: 'Lower interest rates reduce returns on financial assets held in the domestic currency (1 mark). Hot money/capital outflows occur as investors seek higher returns abroad, reducing demand for the currency (1 mark). The currency depreciates, making exports cheaper in foreign markets and imports more expensive domestically (1 mark). Net exports (X-M) increase, contributing to higher AD (1 mark).' },
      { q: 'Evaluate the usefulness of the multiplier concept for government economic policy.', marks: 6, markScheme: 'Useful: helps predict the total impact of fiscal policy changes; guides the size of stimulus/austerity needed; explains why small changes can have large effects. Limitations: the actual multiplier is uncertain and varies with economic conditions; time lags mean the full effect takes time; crowding out may reduce the effective multiplier; in an open economy with high imports the multiplier is small; near full employment it may cause inflation rather than real growth. Evaluation: the multiplier is a useful theoretical concept but its practical value depends on accurate estimation and timing; it is most relevant during recessions with significant spare capacity and less relevant near full employment.' },
      { q: 'Evaluate the significance of animal spirits for macroeconomic stability.', marks: 6, markScheme: 'Keynes argued that business investment is driven by animal spirits (waves of optimism/pessimism) rather than purely rational calculation. Significance: can cause self-fulfilling booms and busts; explains why investment is the most volatile component of AD; confidence collapses can trigger recessions independent of fundamentals. Policy implications: government may need to manage confidence through communication and credible policy frameworks. Counter-arguments: classical economists argue fundamentals (interest rates, expected returns) matter more; animal spirits are hard to measure or predict; may overstate psychological factors. Evaluation: animal spirits play a role in amplifying cycles but are one factor among many; policy should address both confidence and fundamentals.' },
      { q: 'Explain what is meant by equilibrium national income in the circular flow model.', marks: 3, markScheme: 'Equilibrium national income occurs when planned injections (I + G + X) equal planned withdrawals (S + T + M) (1 mark). At this point, there is no tendency for national income to change (1 mark). If injections exceed withdrawals, income rises; if withdrawals exceed injections, income falls (1 mark).' },
      { q: 'Explain what happens in the AD/AS model when there is a rightward shift in LRAS with no change in AD.', marks: 3, markScheme: 'A rightward shift in LRAS increases the economy\'s productive potential/capacity (1 mark). With AD unchanged, the economy can produce more output at a lower price level (1 mark). This represents non-inflationary growth and an increase in the sustainable level of output (1 mark).' },
      { q: 'Explain why the wealth effect is considered one of the transmission mechanisms of monetary policy.', marks: 3, markScheme: 'When interest rates fall, asset prices (shares, bonds, property) tend to rise (1 mark). Holders of these assets feel wealthier and increase consumption spending (wealth effect) (1 mark). This boosts AD, linking the central bank\'s interest rate decision to changes in spending in the real economy (1 mark).' },
      { q: 'Explain one reason why the Keynesian cross model is a simplification of reality.', marks: 2, markScheme: 'The model assumes a fixed price level, ignoring inflation which occurs when the economy approaches full capacity (1 mark). In reality, increases in AD near full employment cause price rises rather than output increases, which the model does not capture (1 mark).' },
      { q: 'State one withdrawal (leakage) from the circular flow of income.', marks: 1, markScheme: 'Savings (S) / Taxation (T) / Imports (M) (any one for 1 mark).' },
      { q: 'State what happens to AD if the exchange rate depreciates.', marks: 1, markScheme: 'AD increases because exports become cheaper (boosting X) and imports become more expensive (reducing M), so net exports rise (1 mark).' },
      { q: 'Define the term marginal propensity to save.', marks: 2, markScheme: 'The MPS is the proportion/fraction of each additional unit of income (1 mark) that is saved rather than spent on consumption (1 mark).' },
      { q: 'Define the term aggregate supply.', marks: 2, markScheme: 'Aggregate supply is the total output of goods and services (1 mark) that producers in an economy are willing and able to supply at a given price level over a given time period (1 mark).' },
      { q: 'Using an AD/AS diagram, explain the effect of a decrease in corporation tax on the macroeconomy.', marks: 4, diagram: true, markScheme: 'AD/AS diagram showing AD shifting right (1 mark). Lower corporation tax increases post-tax profits, encouraging higher investment spending (1 mark). Higher investment increases the I component of AD (1 mark). The result is higher real output and potentially a higher price level, depending on spare capacity; in the long run, increased investment may also shift LRAS right (1 mark).' },
      { q: 'Explain how a negative multiplier effect can deepen a recession.', marks: 3, markScheme: 'An initial fall in spending (e.g., decline in exports or investment) reduces incomes for households and firms (1 mark). Lower incomes lead to reduced consumption spending, further reducing demand and incomes in successive rounds (1 mark). The cumulative fall in national income is a multiple of the initial decline, amplifying the downturn (1 mark).' },
      { q: 'Explain why the SRAS curve is upward sloping.', marks: 3, markScheme: 'In the short run, some input costs (e.g., wages set by contracts) are fixed or sticky (1 mark). When the price level rises, firms receive higher prices for output while costs remain temporarily unchanged, increasing profit margins (1 mark). Higher profit margins incentivise firms to increase output, so higher price levels lead to higher quantities supplied in the short run (1 mark).' },
      { q: 'If MPC is 0.6, MPT is 0.2, and MPM is 0.1, calculate the value of the multiplier.', marks: 2, markScheme: 'MPW = MPS + MPT + MPM = (1-0.6) + 0.2 + 0.1 = 0.4 + 0.2 + 0.1 = 0.7. However, since MPS = 1 - MPC - MPT - MPM when considering all leakages: k = 1/(1-MPC+MPT+MPM) = 1/(1-0.6+0.2+0.1) = 1/0.7 (1 mark). The multiplier = approximately 1.43 (1 mark).' },
      { q: 'Explain the difference between a demand-side shock and a supply-side shock to the economy.', marks: 3, markScheme: 'A demand-side shock is an unexpected change that shifts the AD curve, e.g., a financial crisis reducing consumer confidence and spending (1 mark). A supply-side shock is an unexpected change that shifts the SRAS or LRAS curve, e.g., an oil price spike increasing production costs (1 mark). Demand shocks move output and prices in the same direction; supply shocks move them in opposite directions (stagflation from negative supply shock) (1 mark).' },
      { q: 'Explain how consumer confidence affects the consumption function.', marks: 3, markScheme: 'Higher consumer confidence means households feel more optimistic about their future income and job security (1 mark). This leads to higher consumption at every level of income and a lower propensity to save (1 mark). The consumption function shifts upward, increasing the autonomous component of consumption and boosting aggregate demand (1 mark).' },
      { q: 'Explain two factors that determine the level of investment in an economy.', marks: 4, markScheme: 'Interest rates: lower rates reduce the cost of borrowing for firms, making more investment projects profitable and increasing investment spending (1 mark)(1 mark). Business confidence/expectations: if firms expect future demand to grow, they are more likely to invest in new capacity; pessimism leads to postponement of investment (1 mark)(1 mark). Other valid: corporation tax rates, technological change, access to credit.' },
      { q: 'Explain why the classical LRAS curve is vertical.', marks: 3, markScheme: 'The classical view holds that in the long run, all prices and wages are fully flexible and adjust to changes in the price level (1 mark). Any increase in AD leads only to higher prices, not higher real output, because the economy automatically returns to full employment (1 mark). Output in the long run is determined solely by supply-side factors (quantity and quality of resources, technology), not by the price level (1 mark).' },
      { q: 'Explain the concept of the marginal propensity to import and its effect on the multiplier.', marks: 3, markScheme: 'The marginal propensity to import (MPM) is the proportion of additional income spent on imported goods and services (1 mark). A higher MPM means more income leaks out of the domestic circular flow with each spending round (1 mark). This reduces the size of the multiplier because less additional income is re-spent domestically, weakening the chain of spending that amplifies the initial injection (1 mark).' },
      { q: 'Explain how fiscal drag can occur during a period of economic growth.', marks: 3, markScheme: 'Fiscal drag occurs when rising nominal incomes push taxpayers into higher tax brackets in a progressive tax system (1 mark). If tax thresholds are not adjusted for inflation, more income is taxed at higher rates even though real income may not have increased significantly (1 mark). This automatically withdraws purchasing power from the economy, dampening the growth in AD without any deliberate policy change (1 mark).' },
      { q: 'Evaluate the view that the classical model of the macroeconomy is more relevant than the Keynesian model for modern economies.', marks: 6, markScheme: 'Classical strengths: wage and price flexibility eventually does occur; supply-side factors determine long-run growth; government intervention can create inefficiencies; independent central banks focus on stable prices. Classical weaknesses: wages are often sticky downward (contracts, minimum wage, unions); recessions can be prolonged without intervention; assumes full employment which may not exist. Keynesian strengths: explains persistent unemployment; justifies counter-cyclical fiscal policy; relevant during severe downturns (2008 crisis). Keynesian weaknesses: may overstate effectiveness of fiscal policy; ignores potential crowding out; long-run government debt risks. Evaluation: both models have value; the classical model is more relevant for long-run analysis and supply-side policy, while the Keynesian model is more useful for understanding short-run fluctuations and recessions; most modern macroeconomics incorporates elements of both.' },
      { q: 'Evaluate the significance of the multiplier effect for an economy that is heavily dependent on imports.', marks: 6, markScheme: 'Theory: the multiplier amplifies initial spending changes through successive rounds of re-spending. In import-heavy economy: high MPM means large leakage at each round; domestic spending effect is reduced; much of the stimulus flows abroad. Implications: fiscal stimulus is less effective at boosting domestic output; export-led strategy may be more appropriate; multiplier for government spending on imported goods is very small. Counter-arguments: imports may include capital goods that boost productive capacity; some multiplier effect still exists; targeted spending on domestic services may have higher multiplier. Evaluation: the multiplier is significantly weakened in open economies with high import propensity; policy-makers must consider the composition of spending and the import content of different sectors when designing stimulus packages.' },
      { q: 'Explain how the circular flow model demonstrates the equality of national income, national output, and national expenditure.', marks: 3, markScheme: 'In the circular flow, firms produce output (national output) and pay incomes to factors of production (national income) (1 mark). Households spend their income on goods and services produced by firms (national expenditure) (1 mark). Each flow represents the same economic activity measured differently, so in equilibrium, national income = national output = national expenditure (1 mark).' },
      { q: 'Explain why a fall in house prices is likely to reduce consumer spending.', marks: 3, markScheme: 'Housing is the main form of wealth for many households; falling prices reduce their perceived wealth (negative wealth effect) (1 mark). Homeowners feel less financially secure and reduce discretionary spending (1 mark). Lower house prices also reduce the ability to borrow against housing equity, further constraining consumption (1 mark).' },
      { q: 'Explain the Keynesian concept of the liquidity preference theory of interest rate determination.', marks: 3, markScheme: 'Keynes argued that the interest rate is determined by the supply of and demand for money (1 mark). People demand money for three motives: transactions (daily spending), precautionary (unexpected expenses), and speculative (holding money to buy bonds when prices fall) (1 mark). The interest rate adjusts to equate money supply (set by the central bank) with money demand; a higher money supply lowers the interest rate (1 mark).' },
      { q: 'Explain why an increase in government spending on infrastructure shifts both AD and LRAS.', marks: 3, markScheme: 'In the short run, infrastructure spending directly increases the G component of AD, shifting it to the right (1 mark). In the long run, completed infrastructure (roads, railways, broadband) reduces costs and increases productivity for firms across the economy (1 mark). This increases the economy\'s productive capacity, shifting LRAS to the right and enabling higher non-inflationary growth (1 mark).' }
    ]
  },
  '3.2.3': {
    name: 'Economic Performance',
    questions: [
      { q: 'State what is meant by a recession.', marks: 1, markScheme: 'Two consecutive quarters of negative real GDP growth (falling output) (1 mark).' },
      { q: 'State one cost of economic growth.', marks: 1, markScheme: 'Environmental degradation / increased inequality / inflation / depletion of non-renewable resources / stress and reduced quality of life (any one for 1 mark).' },
      { q: 'Define the term output gap.', marks: 2, markScheme: 'The output gap is the difference between actual GDP/output (1 mark) and the potential/trend level of GDP/output in the economy (1 mark).' },
      { q: 'State one cause of long-run economic growth.', marks: 1, markScheme: 'Technological innovation / investment in human capital / increase in labour supply / investment in physical capital (any valid cause for 1 mark).' },
      { q: 'Using a diagram, illustrate and explain the phases of the trade (business) cycle.', marks: 4, diagram: true, markScheme: 'Diagram showing real GDP on y-axis and time on x-axis with a wave-like pattern around an upward-sloping trend line (1 mark). Boom/peak: output above trend, low unemployment, rising inflation (1 mark). Recession/trough: output below trend, rising unemployment, falling confidence (1 mark). Recovery/expansion: output growing back towards trend, unemployment falling, confidence improving (1 mark).' },
      { q: 'Explain the difference between actual and potential economic growth.', marks: 3, markScheme: 'Actual growth is the annual percentage change in real GDP (1 mark). Potential growth is the increase in the productive capacity of the economy/rate at which output could grow if all resources were fully employed (1 mark). Actual growth can occur by reducing spare capacity (closing a negative output gap) whereas potential growth requires an increase in resources or productivity (rightward shift of LRAS) (1 mark).' },
      { q: 'Using a Phillips curve diagram, explain the short-run trade-off between inflation and unemployment.', marks: 4, diagram: true, markScheme: 'Correctly drawn short-run Phillips curve (downward sloping) with inflation on y-axis and unemployment on x-axis (1 mark). Movement along the curve illustrates the trade-off: lower unemployment is associated with higher inflation (1 mark). Explanation: as unemployment falls, labour markets tighten, wages are bid up, and firms pass on higher costs as higher prices (1 mark). The trade-off implies policy-makers face a choice between reducing one at the cost of increasing the other (1 mark).' },
      { q: 'Explain why the long-run Phillips curve is vertical according to monetarist theory.', marks: 4, markScheme: 'In the long run, workers adjust their inflation expectations to match actual inflation (1 mark). If the government tries to reduce unemployment below the natural rate using demand stimulus, inflation rises (1 mark). Workers demand higher wages to maintain real wages, returning unemployment to the natural rate but at a higher inflation rate (1 mark). Therefore the long-run Phillips curve is vertical at the natural rate of unemployment; there is no permanent trade-off (1 mark).' },
      { q: 'Explain two possible conflicts between macroeconomic policy objectives.', marks: 4, markScheme: 'Economic growth vs environmental sustainability: rapid growth may increase pollution, resource depletion, and carbon emissions (1 mark). Policies to address environmental concerns (carbon taxes, regulation) may slow growth (1 mark). Low unemployment vs low inflation (Phillips curve): expansionary policy to reduce unemployment may cause demand-pull inflation as the economy approaches capacity (1 mark). Contractionary policy to control inflation may increase unemployment (1 mark).' },
      { q: 'Explain the concept of stagflation and how it challenges the simple Phillips curve.', marks: 3, markScheme: 'Stagflation is the combination of stagnant/falling output, high unemployment, AND rising inflation occurring simultaneously (1 mark). The simple Phillips curve suggests inflation and unemployment move in opposite directions (1 mark). Stagflation (e.g., from an oil price shock shifting SRAS left) shows both can rise together, shifting the Phillips curve outward and undermining the simple trade-off model (1 mark).' },
      { q: 'Explain how automatic stabilisers work during a recession.', marks: 3, markScheme: 'Tax revenues fall automatically as incomes, spending, and profits decline (1 mark). Government spending on unemployment benefits rises automatically as more workers lose their jobs (1 mark). Both effects inject purchasing power into the economy and partially offset the fall in AD, dampening the downturn without requiring deliberate policy action (1 mark).' },
      { q: 'Explain two supply-side causes of long-run economic growth.', marks: 4, markScheme: 'Technological innovation: new technologies increase productivity, enabling more output from the same inputs (1 mark). This shifts LRAS/PPF to the right, increasing potential output (1 mark). Investment in human capital: better education and training improve worker skills and productivity (1 mark). A more skilled workforce can produce higher-value output and adapt to changing economic conditions (1 mark).' },
      { q: 'Explain why economic growth may not lead to improved living standards for all.', marks: 4, markScheme: 'Growth may be unequally distributed, with gains concentrated among high earners while wages for lower-income workers stagnate (1 mark). Environmental costs (pollution, congestion, resource depletion) may reduce quality of life despite higher GDP (1 mark). Growth driven by longer working hours reduces leisure time and may increase stress (1 mark). If growth is focused on luxury/export goods, basic public services may not improve (1 mark).' },
      { q: 'Explain the concept of sustainable economic growth.', marks: 3, markScheme: 'Sustainable growth means increasing output at a rate that can be maintained without creating future economic, social, or environmental problems (1 mark). It requires growth that does not deplete natural resources faster than they can be renewed (1 mark). It also means growth that does not generate unsustainable debt, excessive inflation, or widening inequality (1 mark).' },
      { q: 'Explain how hysteresis effects can increase the natural rate of unemployment.', marks: 3, markScheme: 'Prolonged cyclical unemployment causes workers to lose skills and become demotivated (1 mark). Employers may view long-term unemployed as less employable, reducing their chances of re-employment (1 mark). What began as cyclical unemployment becomes structural, raising the natural rate/NAIRU even after the recession ends (1 mark).' },
      { q: 'Evaluate whether economic growth should be the primary objective of government policy.', marks: 6, markScheme: 'Arguments for: growth increases real incomes, reduces poverty, funds public services, creates employment. It is a necessary condition for improving living standards. Arguments against: growth at any cost may damage the environment, increase inequality, or create unsustainable debt. Other objectives (low inflation, full employment, sustainability) may conflict with maximising growth. May not improve wellbeing if benefits are unequally shared. Evaluation: growth is important but should not be the sole objective; quality, sustainability, and distribution of growth matter as much as quantity. A balanced approach targeting multiple objectives with appropriate weighting is preferable.' },
      { q: 'Evaluate the usefulness of the Phillips curve as a guide for macroeconomic policy.', marks: 6, markScheme: 'Useful: provides framework for understanding inflation-unemployment dynamics; helps set monetary policy (raise rates when unemployment falls); short-run trade-off still observed. Less useful: relationship has been unstable over time; stagflation in 1970s broke the simple version; globalisation has flattened the curve; expectations-augmented version shows no long-run trade-off; supply shocks shift the curve making it unpredictable. Evaluation: the underlying logic remains relevant but the relationship is not stable or precise enough to be a mechanical policy guide; policy-makers must also consider expectations, supply-side conditions, and international factors.' },
      { q: 'Explain the relationship between the trade cycle and unemployment.', marks: 3, markScheme: 'During boom phases, aggregate demand is high, firms expand output and hire more workers, so unemployment falls (1 mark). During recession, AD falls, firms cut output and lay off workers, so cyclical/demand-deficient unemployment rises (1 mark). The trade cycle creates fluctuations in unemployment around the natural rate (1 mark).' },
      { q: 'Explain why export-led growth may be vulnerable to external shocks.', marks: 3, markScheme: 'Export-led growth depends heavily on demand from foreign markets (1 mark). A global recession or slowdown in key trading partners reduces demand for exports, directly reducing the country\'s GDP growth (1 mark). Exchange rate appreciation can also erode export competitiveness, making the growth model fragile to factors outside domestic control (1 mark).' },
      { q: 'Explain what is meant by inclusive growth and why it matters.', marks: 3, markScheme: 'Inclusive growth means economic growth that is broadly shared across society, reducing poverty and inequality (1 mark). It matters because growth that only benefits a few may increase social tensions and political instability (1 mark). It also improves aggregate demand (lower-income households have higher MPC) and ensures broader human capital development (1 mark).' },
      { q: 'State one benefit of economic growth.', marks: 1, markScheme: 'Higher real incomes / reduced poverty / increased employment / higher tax revenue / improved public services (any one for 1 mark).' },
      { q: 'State what is meant by a negative output gap.', marks: 1, markScheme: 'A negative output gap occurs when actual GDP is below potential/trend GDP, indicating spare capacity in the economy (1 mark).' },
      { q: 'Define the term trend rate of growth.', marks: 2, markScheme: 'The trend rate of growth is the long-run average rate at which an economy\'s productive capacity increases over time (1 mark). It reflects the underlying rate of growth of potential output determined by supply-side factors (1 mark).' },
      { q: 'Define the term deflation.', marks: 2, markScheme: 'Deflation is a sustained fall in the general/average price level (1 mark) over a period of time, meaning the inflation rate is negative (1 mark).' },
      { q: 'Using a diagram, explain how a positive output gap is associated with inflationary pressure.', marks: 4, diagram: true, markScheme: 'AD/AS diagram with AD positioned so that actual output exceeds potential output (1 mark). The economy is operating beyond its full capacity level of output (1 mark). Excess demand in factor markets bids up wages and input costs (1 mark). This creates demand-pull inflation as firms raise prices in response to strong demand, shown by the price level rising along the SRAS curve (1 mark).' },
      { q: 'Explain how demand-side policies can affect the trade cycle.', marks: 3, markScheme: 'During recession, expansionary fiscal and monetary policy can boost AD, helping to pull the economy out of the trough (1 mark). During a boom, contractionary policies can be used to reduce AD and prevent overheating and inflation (1 mark). These counter-cyclical policies aim to smooth the trade cycle, reducing the amplitude of fluctuations around the trend (1 mark).' },
      { q: 'Explain two reasons why deflation can be harmful to an economy.', marks: 4, markScheme: 'Consumers may delay purchases expecting further price falls, reducing aggregate demand and creating a deflationary spiral (1 mark). This can lead to falling output, rising unemployment, and further deflation (1 mark). The real value of debt increases, making it harder for borrowers (households, firms, government) to service debts (1 mark). This can lead to defaults, banking problems, and reduced investment and consumption (debt deflation, as described by Irving Fisher) (1 mark).' },
      { q: 'Explain the expectations-augmented Phillips curve.', marks: 4, markScheme: 'The expectations-augmented Phillips curve (Friedman-Phelps) distinguishes between short-run and long-run Phillips curves (1 mark). In the short run, lower unemployment can be achieved by accepting higher inflation if expectations lag behind (1 mark). However, workers eventually adjust their expectations to actual inflation and demand higher wages (1 mark). The economy returns to the natural rate of unemployment but at a higher level of inflation, meaning the long-run Phillips curve is vertical at the NAIRU (1 mark).' },
      { q: 'Explain how technological progress contributes to long-run economic growth.', marks: 3, markScheme: 'Technological progress increases productivity by enabling more output from the same quantity of inputs (1 mark). This shifts the LRAS curve to the right, increasing potential output (1 mark). New technologies also create new industries and products, driving innovation, investment, and employment in growth sectors (1 mark).' },
      { q: 'Explain the difference between a demand-side and supply-side cause of inflation.', marks: 3, markScheme: 'Demand-pull inflation is caused by aggregate demand growing faster than aggregate supply, pulling prices up (1 mark). Cost-push inflation is a supply-side cause: rising production costs (wages, raw materials, energy) push up prices as firms pass on higher costs (1 mark). Demand-pull inflation is associated with rising output while cost-push inflation is associated with falling output (stagflation) (1 mark).' },
      { q: 'Explain how the multiplier and accelerator interact to amplify the trade cycle.', marks: 4, markScheme: 'An initial increase in AD raises output through the multiplier effect (1 mark). Rising output triggers the accelerator, as firms invest to expand capacity to meet growing demand (1 mark). This investment is itself an injection that further boosts AD through the multiplier (1 mark). The cycle works in reverse during downturns: falling demand leads to negative accelerator effects (reduced investment), which reduces AD through the negative multiplier, deepening the recession (1 mark).' },
      { q: 'Explain how improved education can shift the long-run Phillips curve to the left.', marks: 3, markScheme: 'Better education reduces structural unemployment by improving the match between workers\' skills and employer needs (1 mark). This lowers the natural rate of unemployment/NAIRU (1 mark). The vertical long-run Phillips curve shifts to the left, meaning the economy can achieve lower unemployment without generating additional inflation (1 mark).' },
      { q: 'Explain the concept of benign deflation and how it differs from malign deflation.', marks: 3, markScheme: 'Benign deflation results from improvements in technology and productivity that lower production costs and prices while output grows (1 mark). Malign deflation is caused by a collapse in aggregate demand leading to falling prices, rising unemployment, and economic contraction (1 mark). Benign deflation improves living standards while malign deflation creates a deflationary spiral and economic hardship (1 mark).' },
      { q: 'Explain why governments may face a conflict between economic growth and reducing a current account deficit.', marks: 3, markScheme: 'Faster economic growth tends to increase consumer spending, which raises demand for imports (higher marginal propensity to import) (1 mark). This worsens the current account deficit even as GDP grows (1 mark). To reduce the deficit, the government might need to slow growth through contractionary policy, which conflicts directly with the growth objective (1 mark).' },
      { q: 'Evaluate the effectiveness of automatic stabilisers in managing the trade cycle.', marks: 6, markScheme: 'Benefits: act immediately without political delays; provide counter-cyclical support automatically; stabilise household incomes and maintain demand; reduce the severity of recessions. Limitations: cannot prevent recessions, only dampen them; may be insufficient during severe downturns (2008 required additional discretionary policy); size depends on the structure of the tax and benefit system; can create large budget deficits during prolonged recessions. Evaluation: automatic stabilisers are an important first line of defence against cyclical fluctuations but cannot substitute for discretionary policy in severe downturns; their effectiveness depends on the progressivity of the tax system and the generosity of the welfare state.' },
      { q: 'Evaluate the importance of maintaining low and stable inflation for long-term economic performance.', marks: 6, markScheme: 'Benefits of low inflation: preserves purchasing power; reduces uncertainty for business investment planning; maintains international competitiveness; protects those on fixed incomes; anchors expectations reducing policy costs. Costs of maintaining very low inflation: may require high interest rates that slow growth; zero lower bound risk if inflation is too low; some inflation may grease the wheels of the economy (allows real wage adjustment). Evaluation: the consensus target of around 2% balances the costs of inflation against the risks of deflation; low and stable inflation is widely seen as a necessary but not sufficient condition for strong economic performance; it must be complemented by sound fiscal and supply-side policies.' },
      { q: 'Explain the concept of NAIRU and its significance for monetary policy.', marks: 3, markScheme: 'NAIRU (Non-Accelerating Inflation Rate of Unemployment) is the unemployment rate at which inflation neither accelerates nor decelerates (1 mark). If unemployment falls below NAIRU, labour market tightness causes wages to rise faster than productivity, creating inflationary pressure (1 mark). Central banks use estimates of NAIRU to guide interest rate decisions, raising rates when unemployment approaches or falls below this level to prevent inflation (1 mark).' },
      { q: 'Explain how a supply-side shock can cause both higher unemployment and higher inflation simultaneously.', marks: 3, markScheme: 'A negative supply-side shock (e.g., oil price spike) increases firms\' production costs, shifting SRAS to the left (1 mark). Higher costs lead to higher prices (inflation) while the reduction in output causes firms to lay off workers (unemployment rises) (1 mark). This combination of higher inflation and higher unemployment is stagflation, which cannot be easily resolved by demand management alone (1 mark).' },
      { q: 'Explain one way in which globalisation has affected the UK trade cycle.', marks: 3, markScheme: 'Greater trade integration means the UK economy is more exposed to external demand shocks; a global recession reduces demand for UK exports, deepening domestic downturns (1 mark). Financial globalisation means capital flows and financial crises can spread quickly across borders (contagion), as seen in 2008 (1 mark). However, globalisation may also dampen inflation during booms through cheaper imports, potentially moderating the boom phase of the cycle (1 mark).' },
      { q: 'Explain the difference between a demand-deficient recession and a structural decline in an economy.', marks: 3, markScheme: 'A demand-deficient recession is caused by a fall in aggregate demand (e.g., loss of consumer confidence, financial crisis), leading to temporary output loss and cyclical unemployment (1 mark). A structural decline involves long-term changes in the economy such as deindustrialisation or loss of comparative advantage in key sectors (1 mark). Demand-deficient recessions can be addressed through expansionary fiscal and monetary policy, while structural decline requires supply-side reforms, retraining, and economic diversification (1 mark).' }
    ]
  },
  '3.2.4': {
    name: 'Financial Markets & Monetary Policy',
    questions: [
      { q: 'State the UK\'s current inflation target.', marks: 1, markScheme: '2% CPI inflation (1 mark).' },
      { q: 'State one function of the Bank of England.', marks: 1, markScheme: 'Setting the bank rate/interest rates / acting as lender of last resort / maintaining financial stability / issuing banknotes (any one for 1 mark).' },
      { q: 'Define the term monetary policy.', marks: 2, markScheme: 'Monetary policy involves the use of interest rates and/or the money supply (1 mark) by the central bank to influence aggregate demand and achieve macroeconomic objectives such as the inflation target (1 mark).' },
      { q: 'State what is meant by quantitative easing.', marks: 2, markScheme: 'The central bank creates new electronic money (1 mark) to purchase financial assets (typically government bonds) from banks and financial institutions to increase the money supply and stimulate economic activity (1 mark).' },
      { q: 'Explain the transmission mechanism of a rise in the Bank of England base rate on the macroeconomy.', marks: 4, markScheme: 'Higher base rate leads commercial banks to raise their lending and savings rates (1 mark). Higher borrowing costs reduce consumer spending (especially on credit) and business investment (1 mark). Higher savings rates encourage saving over consumption, reducing disposable income available for spending (1 mark). The currency may appreciate due to hot money inflows, reducing net exports. Overall AD falls, reducing inflationary pressure (1 mark).' },
      { q: 'Explain why the Bank of England may use forward guidance as a monetary policy tool.', marks: 3, markScheme: 'Forward guidance involves the central bank communicating its future policy intentions to the public and markets (1 mark). This helps manage expectations, reducing uncertainty for businesses and consumers making investment and spending decisions (1 mark). It can influence long-term interest rates and behaviour even before any actual rate change occurs, enhancing the effectiveness of monetary policy (1 mark).' },
      { q: 'Explain why quantitative easing was used after the 2008 financial crisis.', marks: 4, markScheme: 'Interest rates had been cut to near zero (0.5%) but the economy was still in deep recession (1 mark). Conventional monetary policy was exhausted (zero lower bound) so an unconventional tool was needed (1 mark). QE aimed to increase bank reserves and encourage lending, lower long-term bond yields to reduce borrowing costs (1 mark). It also aimed to boost asset prices (wealth effect) and signal that the Bank would do whatever necessary to support recovery (1 mark).' },
      { q: 'Explain the relationship between bond prices and yields.', marks: 3, markScheme: 'Bonds pay a fixed coupon (interest payment) per year (1 mark). If the market price of the bond rises, the fixed coupon represents a smaller percentage return, so the yield falls (1 mark). Conversely, if the bond price falls, the same fixed coupon represents a higher percentage return, so the yield rises. There is an inverse relationship (1 mark).' },
      { q: 'Explain how commercial banks create money through the credit creation process.', marks: 4, markScheme: 'When a bank receives a deposit, it keeps a fraction as reserves and lends the rest (fractional reserve banking) (1 mark). The loan is spent and deposited in another bank, which also keeps a fraction and lends the rest (1 mark). This process repeats, with each round creating new deposits (money) (1 mark). The money multiplier means an initial deposit can lead to a much larger total increase in the money supply: 1/reserve ratio (1 mark).' },
      { q: 'Explain the concept of a liquidity trap and its implications for monetary policy.', marks: 3, markScheme: 'A liquidity trap occurs when interest rates are so low that people prefer to hold cash rather than bonds (infinite demand for money) (1 mark). Further increases in the money supply are simply held as idle balances rather than being lent or spent (1 mark). Conventional monetary policy becomes ineffective, requiring alternative tools like QE or fiscal policy to stimulate demand (1 mark).' },
      { q: 'Explain two reasons why monetary policy may have limited effectiveness.', marks: 4, markScheme: 'Time lags: changes in interest rates take 18-24 months to have full effect on output and prices, meaning policy may be responding to outdated conditions (1 mark)(1 mark). Zero lower bound: when rates are already very low, there is limited room for further cuts, constraining the Bank\'s ability to stimulate the economy in severe downturns (1 mark)(1 mark). Other valid: inability to target specific sectors, asymmetric effects on borrowers vs savers, limited impact on cost-push inflation.' },
      { q: 'Explain why the MPC (Monetary Policy Committee) is independent from the government.', marks: 3, markScheme: 'Independence removes political pressure to cut rates before elections for short-term popularity (1 mark). This gives monetary policy greater credibility, helping to anchor inflation expectations (1 mark). Credible commitment to the inflation target reduces the costs of maintaining low inflation (lower sacrifice ratio) (1 mark).' },
      { q: 'Explain the concept of moral hazard in banking and how it can lead to financial instability.', marks: 4, markScheme: 'Moral hazard occurs when banks take excessive risks because they believe they will be bailed out by the government if things go wrong (too big to fail) (1 mark). This implicit guarantee means banks do not bear the full cost of risky behaviour (1 mark). Excessive risk-taking (leveraging, subprime lending) can create asset bubbles and systemic risk (1 mark). When the bubble bursts, the financial system faces crisis, as seen in 2007-08 (1 mark).' },
      { q: 'Explain how an appreciation of the exchange rate affects the domestic economy.', marks: 4, markScheme: 'Exports become more expensive in foreign markets, reducing export demand and output in export industries (1 mark). Imports become cheaper, reducing the cost of imported raw materials and consumer goods (1 mark). The current account balance may worsen as exports fall and imports rise (1 mark). Cheaper imports reduce cost-push inflation and increase consumer purchasing power, but domestic producers face increased competition (1 mark).' },
      { q: 'Evaluate the effectiveness of quantitative easing as a monetary policy tool.', marks: 6, markScheme: 'Benefits: increased bank reserves and liquidity during crisis; lowered long-term interest rates; supported asset prices and prevented deflation; signalled commitment to economic recovery. Costs/limitations: uncertain transmission mechanism (banks may not lend more); inflated asset prices disproportionately benefiting wealthy; widened inequality; risk of future inflation when money velocity increases; difficult exit strategy (unwinding risks market disruption). Evaluation: QE was probably necessary to prevent a worse outcome in 2008-09 but its effectiveness diminishes with repeated use; distributional effects are a significant concern; should be seen as an emergency tool rather than a permanent feature of monetary policy.' },
      { q: 'Evaluate the case for and against central bank independence.', marks: 6, markScheme: 'For: removes political manipulation of rates for electoral advantage; credible commitment to inflation target anchors expectations; evidence suggests independent central banks achieve lower average inflation; allows expertise-driven decision-making. Against: unelected officials make decisions with major distributional consequences (democratic deficit); may prioritise inflation over employment excessively; coordination with fiscal policy becomes harder; may lack accountability for errors. Evaluation: independence has broadly been successful in maintaining low inflation but the 2008 crisis exposed limitations; some coordination mechanisms between monetary and fiscal authorities may be needed without compromising core independence.' },
      { q: 'Explain the difference between narrow and broad money.', marks: 3, markScheme: 'Narrow money (M0/monetary base) includes physical currency in circulation plus commercial bank reserves at the central bank (1 mark). Broad money (M4) includes narrow money plus all bank deposits (current accounts, savings accounts) and other liquid financial instruments (1 mark). Broad money is a much larger measure and more relevant for understanding spending and credit in the economy (1 mark).' },
      { q: 'Explain the quantity theory of money (MV = PQ) and its policy implications.', marks: 4, markScheme: 'M = money supply, V = velocity of circulation, P = price level, Q = real output (1 mark). If V and Q are assumed constant (as monetarists argue), then increases in M lead directly to proportional increases in P (inflation) (1 mark). Policy implication: controlling the money supply is the key to controlling inflation (1 mark). Criticism: V is not stable in practice, and the relationship between M and P has weakened in modern economies with complex financial systems (1 mark).' },
      { q: 'Explain the role of financial regulation in preventing banking crises.', marks: 4, markScheme: 'Capital adequacy requirements (Basel accords) ensure banks hold sufficient capital buffers to absorb losses (1 mark). Liquidity requirements ensure banks can meet short-term obligations without fire sales of assets (1 mark). Stress testing evaluates whether banks can withstand adverse economic scenarios (1 mark). Ring-fencing separates retail banking from riskier investment banking activities to protect depositors (1 mark).' },
      { q: 'Explain how negative interest rates are intended to stimulate economic activity.', marks: 3, markScheme: 'Negative rates mean banks are charged for holding excess reserves at the central bank (1 mark). This incentivises banks to lend rather than hold money, increasing credit availability to businesses and consumers (1 mark). It may also discourage saving and encourage spending, and put downward pressure on the exchange rate to boost exports (1 mark).' },
      { q: 'State one role of the financial sector in the economy.', marks: 1, markScheme: 'Channelling funds from savers to borrowers / facilitating payments / managing risk through insurance / providing liquidity (any one for 1 mark).' },
      { q: 'State one tool of monetary policy other than interest rates.', marks: 1, markScheme: 'Quantitative easing / reserve requirements / forward guidance / open market operations (any one for 1 mark).' },
      { q: 'Define the term exchange rate.', marks: 2, markScheme: 'The exchange rate is the price of one currency expressed in terms of another currency (1 mark). It determines how much foreign currency can be purchased with a unit of domestic currency (1 mark).' },
      { q: 'Define the term hot money flows.', marks: 2, markScheme: 'Hot money refers to short-term capital flows that move quickly between countries (1 mark) seeking the highest rate of return, often in response to interest rate differentials or exchange rate expectations (1 mark).' },
      { q: 'Explain the transmission mechanism through which lower interest rates affect consumption.', marks: 4, markScheme: 'Lower rates reduce the cost of borrowing on mortgages, credit cards, and personal loans, increasing disposable income for existing borrowers (1 mark). This encourages new borrowing for consumption, especially on big-ticket items like cars and home improvements (1 mark). Lower saving rates reduce the incentive to save, shifting income towards consumption (1 mark). Rising asset prices (houses, shares) create a positive wealth effect, boosting confidence and spending (1 mark).' },
      { q: 'Explain how quantitative easing is intended to increase bank lending.', marks: 3, markScheme: 'The central bank buys government bonds from commercial banks, crediting their reserve accounts with new electronic money (1 mark). With increased reserves, banks have greater capacity and willingness to lend to businesses and consumers (1 mark). Increased lending creates new deposits (credit creation), expanding the money supply and stimulating economic activity (1 mark).' },
      { q: 'Explain the difference between a fixed and a floating exchange rate system.', marks: 3, markScheme: 'In a fixed system, the government or central bank sets the exchange rate at a specific level and intervenes (buying/selling currency, adjusting interest rates) to maintain it (1 mark). In a floating system, the exchange rate is determined by market forces of supply and demand for the currency (1 mark). Fixed rates provide certainty for trade but require large reserves; floating rates adjust automatically but can be volatile (1 mark).' },
      { q: 'Explain how an increase in UK interest rates relative to other countries affects the exchange rate.', marks: 3, markScheme: 'Higher UK rates increase the return on UK financial assets relative to foreign assets (1 mark). Hot money flows into the UK as investors seek higher returns, increasing demand for sterling (1 mark). The increased demand causes the pound to appreciate against other currencies (1 mark).' },
      { q: 'Explain why excessive credit growth can lead to financial instability.', marks: 3, markScheme: 'Rapid credit growth can fuel asset price bubbles as borrowed money flows into housing and financial markets (1 mark). Lenders may lower lending standards to maintain growth, extending credit to increasingly risky borrowers (1 mark). When the bubble bursts, defaults rise, bank balance sheets deteriorate, and a financial crisis can result, as occurred in 2007-08 (1 mark).' },
      { q: 'Explain the concept of the zero lower bound and its significance for monetary policy.', marks: 3, markScheme: 'The zero lower bound is the point at which nominal interest rates reach or approach zero and cannot be cut further in conventional terms (1 mark). At this point, conventional monetary policy is exhausted as there is no room for further rate cuts to stimulate demand (1 mark). This forces central banks to use unconventional tools such as quantitative easing, negative rates, or forward guidance to provide additional stimulus (1 mark).' },
      { q: 'Explain the role of the lender of last resort function of the Bank of England.', marks: 3, markScheme: 'The Bank of England acts as a lender of last resort by providing emergency liquidity to solvent banks facing temporary cash flow problems (1 mark). This prevents bank runs where depositors panic and withdraw funds, potentially causing an otherwise solvent bank to fail (1 mark). It maintains confidence in the banking system and prevents contagion spreading to other financial institutions (1 mark).' },
      { q: 'Explain how macroprudential regulation differs from monetary policy.', marks: 3, markScheme: 'Monetary policy uses interest rates and money supply to manage aggregate demand and inflation (1 mark). Macroprudential regulation focuses on the stability of the financial system as a whole, using tools like capital buffers, leverage ratios, and loan-to-value limits (1 mark). While monetary policy targets the real economy, macroprudential tools target financial risks that could cause systemic crises (1 mark).' },
      { q: 'Explain why the exchange rate is an important transmission mechanism of monetary policy.', marks: 3, markScheme: 'Changes in interest rates affect the exchange rate through hot money flows (higher rates appreciate the currency) (1 mark). An appreciated currency makes exports more expensive and imports cheaper, reducing net exports and AD (1 mark). This exchange rate channel reinforces the direct effects of interest rate changes on consumption and investment, amplifying the overall monetary policy impact (1 mark).' },
      { q: 'Explain two potential drawbacks of quantitative easing.', marks: 4, markScheme: 'Increased inequality: QE inflates asset prices (shares, property), disproportionately benefiting wealthier households who own more assets (1 mark). This widens the wealth gap and may increase social discontent (1 mark). Risk of future inflation: the large increase in the monetary base could generate inflation if the money velocity increases when the economy recovers (1 mark). Unwinding QE (selling bonds back) is challenging and risks disrupting financial markets (1 mark).' },
      { q: 'Evaluate the view that monetary policy is more effective than fiscal policy in managing the macroeconomy.', marks: 6, markScheme: 'Monetary policy advantages: quicker to implement (MPC meets monthly); independent from political pressures; can target inflation precisely; avoids crowding out. Monetary policy limitations: time lags of 18-24 months; zero lower bound limits effectiveness; asymmetric effects on different sectors; limited effectiveness in liquidity trap. Fiscal policy advantages: can target specific groups/regions; directly affects AD; can address structural issues. Fiscal policy limitations: political delays; crowding out; time lags; may increase national debt. Evaluation: both tools are needed; monetary policy is the primary tool for routine demand management, while fiscal policy is essential during severe downturns; the optimal policy mix depends on economic conditions and the nature of the shock.' },
      { q: 'Evaluate the risks of using unconventional monetary policy tools over an extended period.', marks: 6, markScheme: 'Short-term benefits: prevents deflation and financial collapse; supports economic recovery; lowers borrowing costs for governments and firms. Long-term risks: asset price bubbles from prolonged low rates; zombie firms kept alive (misallocation of resources); moral hazard as markets expect perpetual support; inequality from asset price inflation; central bank credibility may be undermined; exit strategy is difficult without causing market disruption. Evaluation: unconventional tools were necessary as crisis responses but prolonged use creates dependency and distortions; gradual unwinding with clear communication is essential; complementary structural reforms are needed for sustainable recovery.' },
      { q: 'Explain the concept of the money multiplier and why it may not work as theory predicts.', marks: 3, markScheme: 'The money multiplier states that an increase in base money leads to a multiple increase in broad money through credit creation (1/reserve ratio) (1 mark). In practice, banks may choose to hold excess reserves rather than lend (e.g., during uncertainty), breaking the transmission chain (1 mark). Demand for loans may be weak if businesses and consumers are deleveraging, so even available credit does not translate into money supply growth (1 mark).' },
      { q: 'Explain how speculation in foreign exchange markets can cause exchange rate volatility.', marks: 3, markScheme: 'Speculators buy and sell currencies based on expectations of future exchange rate movements rather than trade in goods and services (1 mark). Large speculative flows can cause sharp appreciation or depreciation that does not reflect economic fundamentals (1 mark). This volatility creates uncertainty for businesses engaged in international trade and investment, potentially reducing economic activity (1 mark).' },
      { q: 'Explain how a central bank can use open market operations to influence interest rates.', marks: 3, markScheme: 'Open market operations involve the central bank buying or selling government securities in the open market (1 mark). Buying securities injects money into the banking system, increasing liquidity and putting downward pressure on short-term interest rates (1 mark). Selling securities withdraws money from the banking system, reducing liquidity and pushing interest rates upward (1 mark).' },
      { q: 'Explain why savers and borrowers are affected differently by changes in interest rates.', marks: 3, markScheme: 'Higher interest rates benefit savers by increasing the return on their deposits, encouraging more saving (1 mark). However, borrowers face higher repayment costs on variable-rate loans and mortgages, reducing their disposable income (1 mark). This asymmetry means interest rate changes redistribute income between savers and borrowers, with different effects on consumption depending on which group is larger or more responsive (1 mark).' }
    ]
  },
  '3.2.5': {
    name: 'Fiscal & Supply-Side Policies',
    questions: [
      { q: 'State what is meant by a budget deficit.', marks: 1, markScheme: 'Government spending exceeds government revenue/tax receipts in a given year (1 mark).' },
      { q: 'State one example of an automatic stabiliser.', marks: 1, markScheme: 'Progressive income tax / unemployment benefits / welfare payments (any valid automatic stabiliser for 1 mark).' },
      { q: 'Define the term supply-side policy.', marks: 2, markScheme: 'Supply-side policies are government measures designed to increase the productive capacity/potential output of the economy (1 mark) by shifting LRAS to the right through improving efficiency of markets and factor productivity (1 mark).' },
      { q: 'State the difference between direct and indirect taxes.', marks: 2, markScheme: 'Direct taxes are levied on income, profits, or wealth of individuals and firms (e.g., income tax, corporation tax) (1 mark). Indirect taxes are levied on spending/expenditure on goods and services (e.g., VAT, excise duties) (1 mark).' },
      { q: 'Using a diagram, explain how expansionary fiscal policy affects aggregate demand and the macroeconomy.', marks: 4, diagram: true, markScheme: 'AD/AS diagram with AD shifting right (1 mark). Expansionary fiscal policy involves increased government spending and/or tax cuts (1 mark). This directly increases G or increases C (through higher disposable income), shifting AD right (1 mark). Effect: higher real output and potentially higher price level, with the extent depending on spare capacity (1 mark).' },
      { q: 'Explain how the multiplier enhances the impact of government spending on national income.', marks: 3, markScheme: 'An initial increase in G creates income for recipients who spend a proportion (MPC) on goods and services (1 mark). This generates further income and spending in successive rounds (1 mark). The final increase in national income is a multiple of the initial injection: change in Y = multiplier x change in G (1 mark).' },
      { q: 'Explain the concept of crowding out and why it might limit the effectiveness of expansionary fiscal policy.', marks: 4, markScheme: 'Government borrowing to fund increased spending raises demand in the loanable funds market (1 mark). This pushes up interest rates as the government competes with private borrowers for funds (1 mark). Higher interest rates discourage private sector investment and interest-sensitive consumption (1 mark). The reduction in private spending partially or fully offsets the increase in government spending, reducing the net effect on AD (1 mark).' },
      { q: 'Draw and explain the Laffer curve.', marks: 4, diagram: true, markScheme: 'Bell-shaped curve with tax rate on x-axis (0% to 100%) and tax revenue on y-axis (1 mark). Revenue is zero at 0% and 100% tax rates (1 mark). Revenue rises with tax rate up to an optimal point (T*) then falls as higher rates reduce incentives to work and increase tax avoidance (1 mark). The curve suggests that cutting tax rates from above T* could actually increase revenue (1 mark).' },
      { q: 'Explain two market-based supply-side policies.', marks: 4, markScheme: 'Deregulation: reducing rules and restrictions on businesses lowers compliance costs and barriers to entry (1 mark). This increases competition and incentivises efficiency and innovation (1 mark). Cutting income tax rates: increases the reward for working, potentially increasing labour supply and effort (1 mark). May also attract skilled workers from abroad and reduce tax avoidance (1 mark). Other valid: privatisation, trade union reform, reducing benefits.' },
      { q: 'Explain two interventionist supply-side policies.', marks: 4, markScheme: 'Government investment in education: improves human capital, raising worker productivity and adaptability (1 mark). A more skilled workforce can produce higher-value output and drive innovation (1 mark). Infrastructure spending: roads, railways, broadband reduce transport/communication costs for businesses (1 mark). Improved connectivity increases efficiency and reduces regional disparities (1 mark). Other valid: R&D grants, regional policy, healthcare investment.' },
      { q: 'Explain why supply-side policies typically take a long time to show results.', marks: 3, markScheme: 'Education and training programmes take years for students to complete and enter the workforce with new skills (1 mark). Infrastructure projects have lengthy planning, approval, and construction phases before benefits are realised (1 mark). Institutional and cultural changes (e.g., from deregulation or labour market reform) require gradual adjustment of business practices and behaviour (1 mark).' },
      { q: 'Explain the difference between the structural deficit and the cyclical deficit.', marks: 3, markScheme: 'The cyclical deficit is the part of the budget deficit caused by the economic cycle; in recession, tax receipts fall and benefit spending rises automatically (1 mark). The structural deficit is the underlying deficit that would exist even if the economy were at full employment/potential output (1 mark). Closing the structural deficit requires deliberate policy changes to spending or taxation, whereas the cyclical deficit automatically corrects as the economy recovers (1 mark).' },
      { q: 'Explain why fiscal policy has significant time lags.', marks: 3, markScheme: 'Recognition lag: it takes time to identify that the economy needs intervention through data collection and analysis (1 mark). Decision lag: political processes (parliamentary debates, budget cycles) delay policy formulation and approval (1 mark). Implementation lag: once decided, spending programmes or tax changes take time to implement and affect the economy (1 mark).' },
      { q: 'Explain how privatisation may improve economic efficiency.', marks: 3, markScheme: 'Private ownership creates a profit incentive, motivating managers to cut costs and improve productivity (1 mark). Exposure to market competition forces firms to respond to consumer preferences and innovate (1 mark). Share price discipline and threat of takeover incentivise efficient management compared to state-owned firms that face softer budget constraints (1 mark).' },
      { q: 'Explain how welfare reform can act as a supply-side policy.', marks: 3, markScheme: 'Reducing the level or duration of unemployment benefits lowers the replacement ratio (benefits relative to wages) (1 mark). This increases the financial incentive for unemployed workers to seek and accept work (1 mark). This reduces voluntary and frictional unemployment, increasing the effective labour supply and reducing the natural rate of unemployment (1 mark).' },
      { q: 'Evaluate whether austerity or fiscal stimulus is the better response to a recession.', marks: 6, markScheme: 'Fiscal stimulus: directly boosts AD through the multiplier; prevents hysteresis by maintaining employment; Keynesian argument that deficit spending is appropriate when private sector retrenches. Austerity: reduces government debt/deficit; maintains market confidence in government finances; avoids crowding out; may be necessary if debt is already very high. Counter-arguments: austerity can deepen recession (fiscal multiplier works in reverse); may increase debt-to-GDP ratio if GDP falls faster than debt; stimulus risks inflation and debt unsustainability if poorly targeted. Evaluation: the appropriate response depends on the severity of the recession, existing debt levels, market confidence, and the size of the multiplier; most evidence suggests stimulus is more appropriate during deep recessions with spare capacity, while consolidation is better suited to periods of growth.' },
      { q: 'Evaluate whether free market or interventionist supply-side policies are more likely to increase economic growth.', marks: 6, markScheme: 'Free market: deregulation, tax cuts, and labour market flexibility create incentives for enterprise and investment; reduce costs and bureaucracy; encourage efficiency. But may increase inequality, environmental damage, and exploitation of workers. Interventionist: education, infrastructure, and R&D address market failures in provision of public goods and merit goods; reduce regional inequalities; build human capital. But risk government failure, high cost, and crowding out. Evaluation: both approaches have a role; the optimal mix depends on existing economic conditions, institutional quality, and policy objectives. Evidence suggests a combination is most effective, with free market reforms creating a dynamic business environment while government investment addresses market failures in education, infrastructure, and innovation.' },
      { q: 'Explain two arguments against using the Laffer curve to justify tax cuts.', marks: 4, markScheme: 'The revenue-maximising tax rate (T*) is unknown and likely varies between countries, tax types, and time periods, so policy-makers cannot be sure current rates are above T* (1 mark)(1 mark). Tax cuts reduce revenue in the short run even if they eventually generate growth; this creates budget deficits and may require spending cuts that harm public services (1 mark)(1 mark). Other valid: oversimplifies by assuming one tax rate, ignores equity concerns, empirical evidence is mixed.' },
      { q: 'Explain how infrastructure investment can be both a demand-side and supply-side policy.', marks: 4, markScheme: 'Demand-side: government spending on infrastructure directly increases AD through the G component and creates jobs, boosting incomes and consumption (multiplier effect) (1 mark)(1 mark). Supply-side: completed infrastructure (roads, broadband, energy) reduces costs for businesses, improves connectivity, and increases productive capacity, shifting LRAS right (1 mark)(1 mark).' },
      { q: 'Explain one advantage and one disadvantage of progressive taxation.', marks: 4, markScheme: 'Advantage: takes a higher proportion from those with greater ability to pay, reducing income inequality and funding public services that benefit all (1 mark). This can improve social cohesion and may increase overall welfare if the MPC is higher for lower-income groups (1 mark). Disadvantage: high marginal tax rates may create disincentive effects, reducing labour supply, enterprise, and effort (1 mark). This could reduce tax revenue (Laffer curve argument) and encourage tax avoidance or emigration of high earners (1 mark).' },
      { q: 'State one example of a regressive tax.', marks: 1, markScheme: 'VAT / excise duties on tobacco or alcohol / council tax (any valid regressive tax for 1 mark).' },
      { q: 'State one aim of fiscal policy.', marks: 1, markScheme: 'To manage aggregate demand / to reduce the budget deficit / to redistribute income / to correct market failures / to promote economic growth (any one for 1 mark).' },
      { q: 'Define the term national debt.', marks: 2, markScheme: 'The national debt is the total accumulated amount of money the government owes (1 mark) from all past budget deficits minus any surpluses, financed through the issue of government bonds (1 mark).' },
      { q: 'Define the term fiscal policy.', marks: 2, markScheme: 'Fiscal policy involves the use of government spending and/or taxation (1 mark) to influence aggregate demand and achieve macroeconomic objectives such as growth, employment, and price stability (1 mark).' },
      { q: 'Using a diagram, explain how a rightward shift of LRAS represents the effect of successful supply-side policies.', marks: 4, diagram: true, markScheme: 'AD/LRAS diagram with LRAS shifting to the right (1 mark). The shift represents an increase in the productive capacity of the economy (1 mark). With AD unchanged, the price level falls and real output increases (1 mark). This represents non-inflationary economic growth, increasing potential output and improving the long-run trade-off between inflation and growth (1 mark).' },
      { q: 'Explain why fiscal policy is described as having an automatic and a discretionary component.', marks: 3, markScheme: 'Automatic fiscal policy works through automatic stabilisers (progressive taxes, unemployment benefits) that change government revenue and spending without deliberate action (1 mark). Discretionary fiscal policy involves deliberate changes to tax rates or government spending decided by the Chancellor in the Budget (1 mark). Both components affect AD but automatic stabilisers act immediately while discretionary changes face political and implementation delays (1 mark).' },
      { q: 'Explain how investment in transport infrastructure acts as a supply-side policy.', marks: 3, markScheme: 'Improved transport reduces journey times and costs for businesses transporting goods and workers commuting (1 mark). This increases labour mobility, allows firms to access wider markets, and reduces geographical unemployment (1 mark). Lower transport costs increase productivity and competitiveness, shifting LRAS to the right and increasing the economy\'s potential output (1 mark).' },
      { q: 'Explain the concept of the fiscal multiplier and why its size matters for policy decisions.', marks: 3, markScheme: 'The fiscal multiplier measures how much national income changes for each pound of change in government spending or taxation (1 mark). A large multiplier means fiscal policy is powerful and small spending changes have big effects on output (1 mark). If the multiplier is small (e.g., due to crowding out or high import propensity), fiscal stimulus is less effective and may not justify the resulting increase in national debt (1 mark).' },
      { q: 'Explain how labour market flexibility can reduce the natural rate of unemployment.', marks: 3, markScheme: 'Flexible labour markets allow wages to adjust to match supply and demand conditions, reducing wage rigidity that causes structural unemployment (1 mark). Easier hiring and firing encourages firms to take on workers, reducing frictional unemployment duration (1 mark). Flexible working patterns (part-time, zero-hours contracts) increase labour force participation and reduce mismatches between available jobs and workers (1 mark).' },
      { q: 'Explain why cutting income tax may not always increase labour supply.', marks: 3, markScheme: 'The substitution effect suggests workers supply more labour because the higher net wage makes work more rewarding relative to leisure (1 mark). However, the income effect means workers may need to work fewer hours to achieve their target income, choosing more leisure instead (1 mark). The net effect on labour supply is ambiguous and depends on which effect dominates; for high earners, the income effect may outweigh the substitution effect (1 mark).' },
      { q: 'Explain how trade union reform can be considered a supply-side policy.', marks: 3, markScheme: 'Limiting trade union power reduces their ability to push wages above market-clearing levels (1 mark). This reduces cost-push inflationary pressure and makes labour markets more flexible (1 mark). Lower real wage rigidity reduces structural unemployment and shifts LRAS to the right, increasing the economy\'s productive potential (1 mark).' },
      { q: 'Explain the difference between a proportional, progressive, and regressive tax.', marks: 3, markScheme: 'A proportional tax takes the same percentage of income from all taxpayers regardless of income level (1 mark). A progressive tax takes a higher percentage from those on higher incomes, e.g., income tax with rising marginal rates (1 mark). A regressive tax takes a higher percentage from those on lower incomes, e.g., VAT, which represents a larger proportion of a low earner\'s income (1 mark).' },
      { q: 'Explain two reasons why increased government spending on healthcare can improve economic performance.', marks: 4, markScheme: 'A healthier workforce has lower absenteeism and higher productivity, increasing output per worker (1 mark). This improves labour supply quality and shifts LRAS to the right (1 mark). Better healthcare reduces the economic burden of illness on the welfare system and allows workers to remain economically active for longer (1 mark). Preventive care reduces future treatment costs, freeing resources for other productive uses (1 mark).' },
      { q: 'Explain the concept of government bond yields and their relationship with government borrowing.', marks: 3, markScheme: 'Government bonds are debt securities issued by the government to finance borrowing, paying a fixed coupon (1 mark). If government borrowing increases significantly, the supply of bonds rises, which may push bond prices down and yields up (1 mark). Higher yields mean the government must pay more to service its debt, increasing the opportunity cost of borrowing and potentially crowding out private investment (1 mark).' },
      { q: 'Evaluate the view that the government should always aim to balance the budget.', marks: 6, markScheme: 'For balanced budget: avoids accumulating unsustainable debt; reduces interest payments freeing money for services; maintains market confidence and keeps borrowing costs low; provides fiscal space for future crises. Against: counter-cyclical policy requires deficits in recessions (Keynesian argument); austerity during downturns can deepen recessions; borrowing for productive investment (infrastructure, education) may pay for itself through higher growth; running surpluses during recessions would be procyclical and harmful. Evaluation: a perpetually balanced budget is neither desirable nor necessary; the key is fiscal sustainability over the cycle rather than annual balance; borrowing should be productive and manageable relative to GDP.' },
      { q: 'Evaluate the effectiveness of supply-side policies in reducing unemployment.', marks: 6, markScheme: 'Effective: education and training reduce structural unemployment by improving skills match; deregulation and tax reform increase incentives to work and hire; improved flexibility reduces frictional unemployment. Limitations: long time lags before benefits materialise; cannot address demand-deficient unemployment during recessions; may increase inequality if benefits flow to already-skilled workers; costs of implementation may strain public finances. Evaluation: supply-side policies are essential for reducing the natural rate of unemployment in the long run but are insufficient alone; demand management is needed during cyclical downturns; the optimal approach combines both demand and supply-side measures.' },
      { q: 'Explain how research and development (R&D) tax credits work as a supply-side policy.', marks: 3, markScheme: 'R&D tax credits reduce the tax liability of firms that invest in innovation and product development (1 mark). By lowering the effective cost of R&D, they incentivise firms to invest more in developing new products, processes, and technologies (1 mark). Greater innovation increases productivity and competitiveness, shifting LRAS to the right and driving long-run economic growth (1 mark).' },
      { q: 'Explain two potential problems of a high national debt for an economy.', marks: 4, markScheme: 'Interest payments: a high debt requires large annual interest payments, diverting government spending away from public services and investment (1 mark). This represents an opportunity cost and may require higher future taxes (1 mark). Crowding out: heavy government borrowing increases demand for loanable funds, potentially raising interest rates for private sector borrowers (1 mark). This may reduce private investment and consumption, partially offsetting the expansionary effect of government spending (1 mark).' },
      { q: 'Explain how enterprise zones and regional policy can reduce geographical unemployment.', marks: 3, markScheme: 'Enterprise zones offer tax breaks, simplified planning, and infrastructure support to attract businesses to deprived areas (1 mark). This creates jobs in regions with high unemployment, reducing the geographic mismatch between job vacancies and unemployed workers (1 mark). Improved regional connectivity and investment reduces economic disparities and encourages firms to locate outside major cities, spreading growth more evenly (1 mark).' },
      { q: 'Explain why contractionary fiscal policy might be needed during a period of high economic growth.', marks: 3, markScheme: 'High growth may push actual output above potential output, creating a positive output gap and demand-pull inflation (1 mark). Contractionary fiscal policy (higher taxes and/or lower government spending) reduces aggregate demand to cool the economy (1 mark). This prevents the economy from overheating, stabilises prices, and builds up a fiscal surplus that can be used to fund spending during future downturns (1 mark).' }
    ]
  }
};

if (typeof module !== 'undefined' && module.exports) {
  module.exports = { ECONOMICS_AQA_PRACTICE };
}
